import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { AuditLogEntry, AuditAction, ACTION_SEVERITY_MAP, ACTION_LABEL_MAP } from "@/types/audit-log";
import { createAuditEntry, storeAuditLog, getStoredAuditLogs, clearAuditLogs } from "@/lib/audit-log";
import { format, parseISO } from "date-fns";
import { 
    Search, 
    Trash2, 
    Shield, 
    MoreHorizontal, 
    UserCog, 
    FileText, 
    ChevronDown, 
    ChevronUp, 
    Filter, 
    Clock, 
    User, 
    QrCode,
    AlertTriangle
} from "lucide-react";

// Mock User Data
const MOCK_USERS = [
    { id: "u1", name: "Max Mustermann", email: "max@autohaus.de", company: "Autohaus Mustermann", role: "user", xp: 1250, status: "active" },
    { id: "u2", name: "Frank Weber", email: "manager@autohaus.de", company: "Caravan Center Kiel", role: "manager", xp: 4500, status: "active" },
    { id: "u3", name: "Anna Thitronik", email: "admin@thitronik.de", company: "THITRONIK GmbH", role: "admin", xp: 8000, status: "active" },
    { id: "u4", name: "Julia Schmidt", email: "j.schmidt@camper-service.com", company: "Camper Service Süd", role: "user", xp: 350, status: "inactive" },
    { id: "u5", name: "Tom Bauer", email: "t.bauer@wohnmobile-bauer.de", company: "Wohnmobile Bauer", role: "user", xp: 2100, status: "active" },
];

const ADMIN_ACTOR = { id: "u3", name: "Anna Thitronik" };

export default function AdminDashboardPage() {
    const t = useTranslations("admin");
    const [eventCode, setEventCode] = useState("TH-2026-A");
    const [qrValue, setQrValue] = useState("TH-2026-A");
    const [searchTerm, setSearchTerm] = useState("");
    const [users, setUsers] = useState(MOCK_USERS);
    const [auditLogs, setAuditLogs] = useState<AuditLogEntry[]>(() => getStoredAuditLogs());
    const [filterAction, setFilterAction] = useState<string>("all");
    const [isClearing, setIsClearing] = useState(false);
    const [expandedLogs, setExpandedLogs] = useState<Set<string>>(new Set());

    const addLog = (entry: AuditLogEntry) => {
        storeAuditLog(entry);
        setAuditLogs((prev: AuditLogEntry[]) => [entry, ...prev]);
    };

    const generateCode = () => {
        const newCode = eventCode.toUpperCase();
        setQrValue(newCode);
        
        addLog(createAuditEntry({
            actor_id: ADMIN_ACTOR.id,
            actor_name: ADMIN_ACTOR.name,
            action: "event.code_generated",
            target_label: newCode
        }));
    };

    const handleRoleChange = (userId: string, newRole: string) => {
        const user = users.find((u: any) => u.id === userId);
        if (!user) return;
        
        const oldRole = user.role;
        setUsers(users.map((u: any) => u.id === userId ? { ...u, role: newRole } : u));
        
        addLog(createAuditEntry({
            actor_id: ADMIN_ACTOR.id,
            actor_name: ADMIN_ACTOR.name,
            action: "user.role_changed",
            target_id: userId,
            target_label: user.name,
            details: { from: oldRole, to: newRole }
        }));
    };

    const handleDeleteUser = (userId: string) => {
        const user = users.find((u: any) => u.id === userId);
        if (!user) return;
        
        setUsers(users.filter((u: any) => u.id !== userId));
        
        addLog(createAuditEntry({
            actor_id: ADMIN_ACTOR.id,
            actor_name: ADMIN_ACTOR.name,
            action: "user.deleted",
            target_id: userId,
            target_label: user.name
        }));
    };

    const handleClearLogs = (e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();
        
        if (!isClearing) {
            setIsClearing(true);
            setTimeout(() => setIsClearing(false), 3000);
            return;
        }
        
        console.log("ACTION: Clearing audit logs");
        clearAuditLogs();
        setAuditLogs([]);
        setExpandedLogs(new Set());
        setIsClearing(false);
    };

    const toggleLogExpansion = (id: string) => {
        const newExpanded = new Set(expandedLogs);
        if (newExpanded.has(id)) {
            newExpanded.delete(id);
        } else {
            newExpanded.add(id);
        }
        setExpandedLogs(newExpanded);
    };

    const filteredLogs = auditLogs.filter((log: AuditLogEntry) => 
        filterAction === "all" || log.action === filterAction
    );

    return (
        <RoleGuard requiredRole="admin">
            <div className="max-w-4xl mx-auto space-y-8">
                <div>
                    <h1 className="text-3xl font-extrabold text-brand-navy tracking-tight">Admin Dashboard</h1>
                    <p className="text-muted-foreground mt-2">
                        Verwaltung von Events, QR-Codes und User-Rollen für die THITRONIK Akademie.
                    </p>
                </div>

                <Tabs defaultValue="events" className="w-full">
                    <TabsList className="grid w-full grid-cols-3 md:w-[500px]">
                        <TabsTrigger value="events">{t('tabs.events')}</TabsTrigger>
                        <TabsTrigger value="users">{t('tabs.users')}</TabsTrigger>
                        <TabsTrigger value="audit">{t('tabs.audit')}</TabsTrigger>
                    </TabsList>

                    <TabsContent value="events" className="mt-6">
                        <div className="grid md:grid-cols-2 gap-6">
                            {/* Generator UI */}
                            <Card>
                                <CardHeader>
                                    <CardTitle>QR-Code Generator</CardTitle>
                                    <CardDescription>
                                        Erstellen Sie einen Event-Code, den die Teilnehmer scannen können.
                                    </CardDescription>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="eventCode">Event/Raum-Code</Label>
                                        <div className="flex gap-2">
                                            <Input
                                                id="eventCode"
                                                value={eventCode}
                                                onChange={(e) => setEventCode(e.target.value)}
                                                placeholder="z.B. TH-2026-A"
                                                className="font-mono uppercase"
                                                maxLength={12}
                                            />
                                            <Button onClick={generateCode}>Generieren</Button>
                                        </div>
                                    </div>

                                    <div className="p-4 bg-muted rounded-xl text-sm text-muted-foreground">
                                        <p>💡 <b>Tipp:</b> Projizieren Sie diesen QR-Code über den Beamer im Schulungsraum.</p>
                                    </div>
                                </CardContent>
                            </Card>

                            {/* QR Code Display */}
                            <Card className="flex flex-col items-center justify-center p-8 bg-white border-2 border-brand-sky/20">
                                <motion.div
                                    key={qrValue}
                                    initial={{ scale: 0.8, opacity: 0 }}
                                    animate={{ scale: 1, opacity: 1 }}
                                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                                    className="bg-white p-4 rounded-xl shadow-sm border border-border"
                                >
                                    <QRCodeSVG
                                        value={qrValue}
                                        size={200}
                                        level={"H"}
                                        includeMargin={false}
                                        fgColor="#1D3661" // THITRONIK Navy
                                    />
                                </motion.div>
                                <div className="mt-6 text-center">
                                    <Badge variant="outline" className="text-lg px-4 py-1 font-mono bg-muted/50 border-brand-navy/20">
                                        {qrValue}
                                    </Badge>
                                    <p className="text-sm text-muted-foreground mt-2">
                                        Teilnehmer können diesen Code am Handy eingeben oder scannen.
                                    </p>
                                </div>
                            </Card>
                        </div>
                    </TabsContent>

                    <TabsContent value="users" className="mt-6">
                        <Card>
                            <CardHeader className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                <div>
                                    <CardTitle>Benutzerverwaltung</CardTitle>
                                    <CardDescription>Accounts, Rollen und XP-Stände aller Campus-Teilnehmer verwalten.</CardDescription>
                                </div>
                                <div className="relative w-full md:w-64">
                                    <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                                    <Input
                                        type="search"
                                        placeholder="Suchen (Name, Firma...)"
                                        className="w-full pl-8"
                                        value={searchTerm}
                                        onChange={(e) => setSearchTerm(e.target.value)}
                                    />
                                </div>
                            </CardHeader>
                            <CardContent>
                                <div className="rounded-md border">
                                    <Table>
                                        <TableHeader className="bg-muted/50">
                                            <TableRow>
                                                <TableHead>Benutzer</TableHead>
                                                <TableHead>Firma</TableHead>
                                                <TableHead>XP</TableHead>
                                                <TableHead>Rolle</TableHead>
                                                <TableHead className="text-right">Aktionen</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase()) || u.company.toLowerCase().includes(searchTerm.toLowerCase())).map((user) => (
                                                <TableRow key={user.id}>
                                                    <TableCell>
                                                        <div className="font-medium">{user.name}</div>
                                                        <div className="text-xs text-muted-foreground">{user.email}</div>
                                                    </TableCell>
                                                    <TableCell>{user.company}</TableCell>
                                                    <TableCell>
                                                        <Badge variant="outline" className="font-mono bg-brand-sky/5 border-brand-sky/20">{user.xp}</Badge>
                                                    </TableCell>
                                                    <TableCell>
                                                        <Select value={user.role} onValueChange={(val) => handleRoleChange(user.id, val)}>
                                                            <SelectTrigger className={`w-[130px] h-8 text-xs font-semibold
                                                                ${user.role === 'admin' ? 'text-destructive border-destructive/50' :
                                                                    user.role === 'manager' ? 'text-brand-sky border-brand-sky/50' : ''}
                                                            `}>
                                                                <SelectValue placeholder="Rolle" />
                                                            </SelectTrigger>
                                                            <SelectContent>
                                                                <SelectItem value="user"><span className="flex items-center gap-2"><UserCog className="w-3 h-3" /> Händler</span></SelectItem>
                                                                <SelectItem value="manager"><span className="flex items-center gap-2 text-brand-sky"><Shield className="w-3 h-3" /> Manager</span></SelectItem>
                                                                <SelectItem value="admin"><span className="flex items-center gap-2 text-destructive"><Shield className="w-3 h-3" /> Admin</span></SelectItem>
                                                            </SelectContent>
                                                        </Select>
                                                    </TableCell>
                                                    <TableCell className="text-right">
                                                        <div className="flex justify-end gap-2">
                                                            <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-brand-navy">
                                                                <MoreHorizontal className="h-4 w-4" />
                                                            </Button>
                                                            <Button 
                                                                variant="ghost" 
                                                                size="icon" 
                                                                className="h-8 w-8 text-muted-foreground hover:text-destructive"
                                                                onClick={() => handleDeleteUser(user.id)}
                                                            >
                                                                <Trash2 className="h-4 w-4" />
                                                            </Button>
                                                        </div>
                                                    </TableCell>
                                                </TableRow>
                                            ))}
                                            {users.length === 0 && (
                                                <TableRow>
                                                    <TableCell colSpan={5} className="h-24 text-center">Keine Benutzer gefunden.</TableCell>
                                                </TableRow>
                                            )}
                                        </TableBody>
                                    </Table>
                                </div>
                            </CardContent>
                        </Card>
                    </TabsContent>

                    <TabsContent value="audit" className="mt-6">
                        <Card>
                            <CardHeader className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                <div>
                                    <CardTitle className="flex items-center gap-2">
                                        <FileText className="w-5 h-5 text-brand-sky" />
                                        {t('audit.title')}
                                    </CardTitle>
                                    <CardDescription>{t('audit.description')}</CardDescription>
                                </div>
                                <div className="flex items-center gap-2">
                                    <Select value={filterAction} onValueChange={setFilterAction}>
                                        <SelectTrigger className="w-[180px]">
                                            <div className="flex items-center gap-2">
                                                <Filter className="w-3 h-3 opacity-50" />
                                                <SelectValue placeholder={t('audit.filterAll')} />
                                            </div>
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">{t('audit.filterAll')}</SelectItem>
                                            {Object.keys(ACTION_LABEL_MAP).map((key) => (
                                                <SelectItem key={key} value={key}>{t(`audit.actions.${key}`)}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    <Button 
                                        variant="outline" 
                                        size="sm" 
                                        onClick={handleClearLogs}
                                        className={isClearing ? "text-destructive border-destructive" : ""}
                                    >
                                        <Trash2 className="w-4 h-4 mr-2" />
                                        {isClearing ? t('audit.clearConfirm') : t('audit.clearLog')}
                                    </Button>
                                </div>
                            </CardHeader>
                            <CardContent>
                                <div className="rounded-md border">
                                    <Table>
                                        <TableHeader className="bg-muted/50">
                                            <TableRow>
                                                <TableHead className="w-[180px]">{t('audit.columns.timestamp')}</TableHead>
                                                <TableHead>{t('audit.columns.actor')}</TableHead>
                                                <TableHead>{t('audit.columns.action')}</TableHead>
                                                <TableHead>{t('audit.columns.target')}</TableHead>
                                                <TableHead className="w-[50px]"></TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {filteredLogs.map((log, index) => (
                                                <>
                                                    <motion.tr
                                                        key={log.id}
                                                        initial={{ opacity: 0, y: -4 }}
                                                        animate={{ opacity: 1, y: 0 }}
                                                        transition={{ delay: index * 0.03 }}
                                                        className="border-b"
                                                    >
                                                        <TableCell className="font-mono text-xs text-muted-foreground">
                                                            <div className="flex items-center gap-2">
                                                                <Clock className="w-3 h-3" />
                                                                {format(parseISO(log.timestamp), "dd.MM.yyyy HH:mm:ss")}
                                                            </div>
                                                        </TableCell>
                                                        <TableCell>
                                                            <div className="flex items-center gap-2 font-medium">
                                                                <User className="w-3 h-3 text-brand-sky" />
                                                                {log.actor_name}
                                                            </div>
                                                        </TableCell>
                                                        <TableCell>
                                                            <Badge 
                                                                variant="outline" 
                                                                className={`
                                                                    ${log.severity === 'info' ? 'bg-brand-sky/10 text-brand-sky border-brand-sky/20' :
                                                                      log.severity === 'warning' ? 'bg-amber-500/10 text-amber-600 border-amber-500/20' :
                                                                      'bg-destructive/10 text-destructive border-destructive/20'}
                                                                `}
                                                            >
                                                                {t.has(`audit.actions.${log.action}`) ? t(`audit.actions.${log.action}`) : log.action}
                                                            </Badge>
                                                        </TableCell>
                                                        <TableCell>
                                                            {log.target_label && (
                                                                <div className="flex items-center gap-2 text-sm">
                                                                    {log.action === 'event.code_generated' ? <QrCode className="w-3 h-3" /> : <Shield className="w-3 h-3" />}
                                                                    {log.target_label}
                                                                </div>
                                                            )}
                                                        </TableCell>
                                                        <TableCell>
                                                            {log.details && (
                                                                <Button 
                                                                    variant="ghost" 
                                                                    size="icon" 
                                                                    className="h-8 w-8"
                                                                    onClick={() => toggleLogExpansion(log.id)}
                                                                >
                                                                    {expandedLogs.has(log.id) ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                                                                </Button>
                                                            )}
                                                        </TableCell>
                                                    </motion.tr>
                                                    {expandedLogs.has(log.id) && log.details && (
                                                        <TableRow className="bg-muted/30">
                                                            <TableCell colSpan={5} className="p-4">
                                                                <pre className="text-xs font-mono bg-muted p-3 rounded-lg border overflow-x-auto">
                                                                    {JSON.stringify(log.details, null, 2)}
                                                                </pre>
                                                            </TableCell>
                                                        </TableRow>
                                                    )}
                                                </>
                                            ))}
                                            {filteredLogs.length === 0 && (
                                                <TableRow>
                                                    <TableCell colSpan={5} className="h-32 text-center">
                                                        <div className="flex flex-col items-center justify-center text-muted-foreground gap-2">
                                                            <AlertTriangle className="w-8 h-8 opacity-20" />
                                                            <p>{t('audit.emptyState')}</p>
                                                        </div>
                                                    </TableCell>
                                                </TableRow>
                                            )}
                                        </TableBody>
                                    </Table>
                                </div>
                            </CardContent>
                        </Card>
                    </TabsContent>

                </Tabs>
            </div>
        </RoleGuard>
    );
}

"use client"

import React, { Suspense, useState, useCallback, useEffect } from "react"
import { PremiumBackground } from "@/components/layout/premium-background"
import { motion } from "framer-motion"
import { Button } from "@/components/ui/button"
import Link from "next/link"
import { ArrowLeft, Brain } from "lucide-react"
import { useParams, useSearchParams } from "next/navigation"
import FillTheGapGame from "@/components/games/fill-the-gap-game"
import { RoleGuard } from "@/components/auth/role-guard"
import { useBroadcastRoom } from "@/lib/multiplayer/useBroadcastRoom"
import { RoomLobby } from "@/lib/multiplayer/RoomLobby"
import { Scoreboard } from "@/lib/multiplayer/Scoreboard"
import { buildRoomUrl } from "@/lib/multiplayer/roomUtils"

function FillTheGapMultiplayer({ roomId, role: initialRole, locale }: { roomId: string; role: "host" | "participant", locale: string }) {
  const [playerName, setPlayerName] = useState("")
  const [nameSet, setNameSet] = useState(initialRole === "host")

  const {
      room, participants, clientId, updateGameState, setStatus, updateParticipantScore,
  } = useBroadcastRoom<any>({
      roomId,
      gameId: "fill-the-gap",
      role: initialRole,
      playerName: initialRole === "host" ? "Host" : playerName,
      initialGameState: { started: false },
  })

  const roomUrl = buildRoomUrl(locale, "fill-the-gap", roomId, "participant")

  const handleNameSubmit = useCallback((name: string) => {
      setPlayerName(name)
      setNameSet(true)
  }, [])

  const startGame = useCallback(() => {
      setStatus("running")
      updateGameState(() => ({ started: true }))
  }, [setStatus, updateGameState])

  const handleFinished = (score: number) => {
      updateParticipantScore(clientId, score)
      // Switch to scoreboard after a short delay
      setTimeout(() => {
        if (initialRole === "host") setStatus("finished")
      }, 2000)
  }

  // Name input
  if (!nameSet) {
      return (
          <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 flex items-center justify-center p-4">
              <RoomLobby roomId={roomId} roomUrl={roomUrl} isHost={false} participants={participants}
                  hostName={room?.host.name ?? "Host"} onStart={() => {}} onNameSubmit={handleNameSubmit} showNameInput />
          </div>
      )
  }

  // Lobby
  if (room?.status === "lobby") {
      return (
          <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 flex flex-col items-center justify-center p-4">
              <div className="absolute top-4 left-4 z-20">
                  <Link href={`/${locale}/games`}><Button variant="ghost" className="gap-2 text-white hover:bg-white/20"><ArrowLeft className="w-4 h-4" /> Zurück</Button></Link>
              </div>
              <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} className="text-3xl font-bold text-white mb-6 flex items-center gap-3">
                  Multiplayer Lückentext
              </motion.div>
              <RoomLobby roomId={roomId} roomUrl={roomUrl} isHost={initialRole === "host"} participants={participants}
                  hostName={room?.host.name ?? "Host"} onStart={startGame} />
          </div>
      )
  }

  // Finished
  if (room?.status === "finished") {
      return (
          <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 flex items-center justify-center p-4">
              <Scoreboard participants={participants} hostName={room?.host.name ?? "Host"} isHost={initialRole === "host"} onPlayAgain={() => {
                 participants.forEach((p) => updateParticipantScore(p.id, 0))
                 setStatus("lobby")
                 updateGameState(() => ({ started: false }))
              }} />
          </div>
      )
  }

  return (
    <PremiumBackground>
      <div className="min-h-screen p-4 md:p-8">
        <motion.div
           initial={{ opacity: 0, y: 20 }}
           animate={{ opacity: 1, y: 0 }}
           className="max-w-4xl mx-auto space-y-6"
        >
          <div className="flex items-center gap-4 mb-4">
             <Link href={`/${locale}/games`}><Button variant="ghost" className="text-white hover:bg-white/10"><ArrowLeft className="w-4 h-4 mr-2" /> Beenden</Button></Link>
             <h1 className="text-2xl font-bold text-white">Live Lückentext</h1>
          </div>
          <FillTheGapGame onFinished={handleFinished} />
        </motion.div>
      </div>
    </PremiumBackground>
  )
}

function FillTheGapPageInner() {
  const params = useParams()
  const searchParams = useSearchParams()
  const locale = (params?.locale as string) || "de"
  const roomId = searchParams.get("room")
  const role = searchParams.get("role") as "host" | "participant" | null

  if (roomId && (role === "host" || role === "participant")) {
      return (
          <RoleGuard requiredRole="user">
              <FillTheGapMultiplayer roomId={roomId} role={role} locale={locale} />
          </RoleGuard>
      )
  }

  return (
    <PremiumBackground>
      <div className="min-h-screen p-4 md:p-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="max-w-4xl mx-auto space-y-6"
        >
          {/* Header mit Zurück-Button */}
          <div className="flex items-center gap-4 mb-8">
            <Button variant="ghost" size="icon" className="text-white hover:bg-white/10" asChild>
              <Link href={`/${locale}/games`}>
                <ArrowLeft className="h-5 w-5" />
              </Link>
            </Button>
            <div>
              <h1 className="text-3xl font-bold text-white">Lückentext</h1>
              <p className="text-white/70">Fülle die Lücken in Sätzen über Thitronik-Produkte und Einbau-Wissen.</p>
            </div>
          </div>

          <FillTheGapGame />
        </motion.div>
      </div>
    </PremiumBackground>
  )
}

export default function FillTheGapPage() {
  return (
      <Suspense fallback={<div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950" />}>
          <FillTheGapPageInner />
      </Suspense>
  )
}

"use client";

import { useSearchParams } from "next/navigation";
import { useState, useCallback, Suspense } from "react";
import { RoleGuard } from "@/components/auth/role-guard";
import { FindErrorQuiz } from "@/components/tools/find-error-quiz";
import { useBroadcastRoom } from "@/lib/multiplayer/useBroadcastRoom";
import { RoomLobby } from "@/lib/multiplayer/RoomLobby";
import { Scoreboard } from "@/lib/multiplayer/Scoreboard";
import { buildRoomUrl } from "@/lib/multiplayer/roomUtils";
import { MSG } from "@/lib/multiplayer/types";
import { motion } from "framer-motion";
import { ArrowLeft, Search, CheckCircle2, AlertCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import Link from "next/link";

// Error zones matching the singleplayer component
const ERROR_ZONES = [
    { id: "error-1", x: 65, y: 35, w: 8, h: 8, isError: true, desc: "Massekabel an Pluspol angeschlossen!" },
    { id: "error-2", x: 25, y: 70, w: 10, h: 10, isError: true, desc: "CAN-Bus Stecker im falschen Port!" },
    { id: "decoy-1", x: 40, y: 40, w: 15, h: 15, isError: false, desc: "WiPro III Zentrale – alles korrekt." },
    { id: "decoy-2", x: 80, y: 80, w: 12, h: 12, isError: false, desc: "Fahrzeugbatterie – Verkabelung intakt." },
];

const TOTAL_ERRORS = ERROR_ZONES.filter((z) => z.isError).length;

interface FindErrorGameState {
    phase: "waiting" | "playing" | "finished";
    found: Record<string, string[]>; // participantId → found error IDs
    clicks: Record<string, Array<{ zoneId: string; timestamp: number }>>;
}

const INITIAL_STATE: FindErrorGameState = { phase: "waiting", found: {}, clicks: {} };

function FindErrorMultiplayer({ roomId, role: initialRole }: { roomId: string; role: "host" | "participant" }) {
    const [playerName, setPlayerName] = useState("");
    const [nameSet, setNameSet] = useState(initialRole === "host");
    const [feedback, setFeedback] = useState<string | null>(null);

    const { room, participants, clientId, sendMessage, updateGameState, setStatus, updateParticipantScore } =
        useBroadcastRoom<FindErrorGameState>({
            roomId, gameId: "find-error", role: initialRole,
            playerName: initialRole === "host" ? "Host" : playerName,
            initialGameState: INITIAL_STATE,
        });

    const roomUrl = buildRoomUrl("de", "find-error", roomId, "participant");
    const gameState = room?.gameState ?? INITIAL_STATE;
    const myFound = gameState.found[clientId] ?? [];

    const handleNameSubmit = useCallback((name: string) => { setPlayerName(name); setNameSet(true); }, []);

    const startGame = useCallback(() => {
        setStatus("running");
        updateGameState(() => ({ phase: "playing", found: {}, clicks: {} }));
    }, [setStatus, updateGameState]);

    const handleZoneClick = useCallback((zone: typeof ERROR_ZONES[0]) => {
        if (gameState.phase !== "playing") return;

        if (zone.isError) {
            if (!myFound.includes(zone.id)) {
                setFeedback(`✅ ${zone.desc}`);
                updateGameState((prev) => {
                    const newFound = { ...prev.found, [clientId]: [...(prev.found[clientId] ?? []), zone.id] };
                    return { ...prev, found: newFound };
                });
                // Score: first to find gets more points
                const allFoundThis = Object.values(gameState.found).flat().filter((id) => id === zone.id).length;
                const points = allFoundThis === 0 ? 500 : 250; // first finder gets bonus
                const p = participants.find((pp) => pp.id === clientId);
                if (p) updateParticipantScore(clientId, (p.score || 0) + points);
            }
        } else {
            setFeedback(`ℹ️ ${zone.desc}`);
        }
        setTimeout(() => setFeedback(null), 3000);
    }, [gameState, myFound, clientId, participants, updateGameState, updateParticipantScore]);

    // Check if all errors found by any player
    const allErrorsFound = ERROR_ZONES.filter((z) => z.isError).every((z) =>
        Object.values(gameState.found).flat().includes(z.id)
    );

    const finishGame = useCallback(() => {
        updateGameState((prev) => ({ ...prev, phase: "finished" }));
        setStatus("finished");
    }, [updateGameState, setStatus]);

    const playAgain = useCallback(() => {
        participants.forEach((p) => updateParticipantScore(p.id, 0));
        setStatus("lobby");
        setFeedback(null);
        updateGameState(() => INITIAL_STATE);
    }, [participants, updateParticipantScore, setStatus, updateGameState]);

    if (!nameSet) {
        return (
            <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 flex items-center justify-center p-4">
                <RoomLobby roomId={roomId} roomUrl={roomUrl} isHost={false} participants={participants}
                    hostName={room?.host.name ?? "Host"} onStart={() => {}} onNameSubmit={handleNameSubmit} showNameInput />
            </div>
        );
    }

    if (room?.status === "lobby" || gameState.phase === "waiting") {
        return (
            <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 flex flex-col items-center justify-center p-4">
                <div className="absolute top-4 left-4 z-20">
                    <Link href="/games"><Button variant="ghost" className="gap-2 text-white hover:bg-white/20"><ArrowLeft className="w-4 h-4" /> Zurück</Button></Link>
                </div>
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-3xl font-bold text-white mb-6 flex items-center gap-3">
                    <Search className="w-8 h-8 text-brand-lime" /> Multiplayer Fehlersuche
                </motion.div>
                <RoomLobby roomId={roomId} roomUrl={roomUrl} isHost={initialRole === "host"} participants={participants}
                    hostName={room?.host.name ?? "Host"} onStart={startGame} />
            </div>
        );
    }

    if (room?.status === "finished" || gameState.phase === "finished") {
        return (
            <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 flex items-center justify-center p-4">
                <Scoreboard participants={participants} hostName={room?.host.name ?? "Host"} isHost={initialRole === "host"} onPlayAgain={playAgain} />
            </div>
        );
    }

    // Playing phase
    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-900 to-slate-950 text-white p-4">
            <div className="max-w-4xl mx-auto">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-xl font-bold flex items-center gap-2">
                        <Search className="w-5 h-5 text-brand-lime" /> Race: Finde die Fehler!
                    </h2>
                    <div className="text-sm text-white/60">{myFound.length}/{TOTAL_ERRORS} gefunden</div>
                </div>

                {/* Live found indicators */}
                <div className="flex gap-2 mb-4 overflow-x-auto pb-2">
                    {participants.map((p) => {
                        const pFound = gameState.found[p.id]?.length ?? 0;
                        return (
                            <div key={p.id} className="flex-shrink-0 px-3 py-1.5 rounded-lg bg-white/10 border border-white/10 text-xs font-bold">
                                {p.name}: {pFound}/{TOTAL_ERRORS}
                            </div>
                        );
                    })}
                </div>

                {/* Diagram with clickable zones */}
                <div className="relative rounded-2xl overflow-hidden bg-slate-800 border border-white/10">
                    <img src="/wiring_diagram_error.png" alt="Schaltplan" className="w-full h-auto max-h-[500px] object-contain" />
                    {ERROR_ZONES.map((zone) => {
                        const isFound = myFound.includes(zone.id);
                        return (
                            <div
                                key={zone.id}
                                onClick={() => handleZoneClick(zone)}
                                className={`absolute cursor-pointer border-2 rounded-lg transition-all hover:bg-white/10 ${
                                    isFound && zone.isError ? "border-brand-lime bg-brand-lime/20" : "border-transparent"
                                }`}
                                style={{ left: `${zone.x}%`, top: `${zone.y}%`, width: `${zone.w}%`, height: `${zone.h}%` }}
                            >
                                {isFound && zone.isError && (
                                    <div className="absolute -top-2 -right-2"><CheckCircle2 className="w-5 h-5 text-brand-lime" /></div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {/* Feedback toast */}
                {feedback && (
                    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="mt-4 p-4 rounded-xl bg-white/10 border border-white/10 text-sm font-medium">
                        {feedback}
                    </motion.div>
                )}

                {initialRole === "host" && allErrorsFound && (
                    <Button onClick={finishGame} className="w-full mt-4 bg-brand-lime text-brand-navy font-bold">Spiel beenden 🏆</Button>
                )}
            </div>
        </div>
    );
}

