        setTimeout(() => {
            setIsSaving(false);
            setSaved(true);
            setTimeout(() => setSaved(false), 3000);
        }, 1000);
    };

    const handleIslandUpdate = (field: string, value: any) => {
        const updated = { ...selectedIsland, [field]: value };
        setSelectedIsland(updated);
        setIslands(islands.map(i => i.id === updated.id ? updated : i));
