                            onClick={() => {
                                setIsEditorMode(true);
                                setSelectedIsland({ id: 'new', name: 'Neue Insel', icon: '📝', xp: 0, status: 'locked', desc: '', active: false });
                                setCmsBlocks([]);
                            }}
