export default function QRCheckinPage() {
    const [scanResult, setScanResult] = useState<string | null>(null);
    const [scannerActive, setScannerActive] = useState(false);
    const [manualCode, setManualCode] = useState("");
    const [checkedIn, setCheckedIn] = useState(false);
    const scannerRef = useRef<HTMLDivElement>(null);
    const html5QrRef = useRef<any>(null);

    const startScanner = async () => {
        setScannerActive(true);
        try {
            const { Html5Qrcode } = await import("html5-qrcode");
            const scanner = new Html5Qrcode("qr-reader");
            html5QrRef.current = scanner;
            await scanner.start(
                { facingMode: "environment" },
                { fps: 10, qrbox: { width: 250, height: 250 } },
                (decodedText: string) => {
                    setScanResult(decodedText);
                    scanner.stop().catch(() => { });
                    setScannerActive(false);
                    handleCheckin(decodedText);
                },
                () => { }
            );
        } catch (err) {
            console.error("Scanner error:", err);
            setScannerActive(false);
        }
    };

    const stopScanner = () => {
        if (html5QrRef.current) {
            html5QrRef.current.stop().catch(() => { });
            setScannerActive(false);
        }
    };

    const handleCheckin = (code: string) => {
        // Simulate check-in
        setScanResult(code);
        setCheckedIn(true);
    };

    const handleManualSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (manualCode.trim()) {
            handleCheckin(manualCode.trim());
        }
    };

    useEffect(() => {
        return () => { stopScanner(); };
    }, []);

    return (
        <motion.div
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            className="max-w-2xl mx-auto space-y-8"
        >
            <div>
                <Badge className="mb-3">Live-Event</Badge>
                <h1>QR Check-in</h1>
                <p className="text-muted-foreground mt-1">
                    Scannen Sie den QR-Code am Veranstaltungsort, um am Live-Event teilzunehmen.
                </p>
            </div>

            {!checkedIn ? (
                <Tabs defaultValue="scan" className="w-full">
                    <TabsList className="grid w-full grid-cols-2">
                        <TabsTrigger value="scan">📷 QR scannen</TabsTrigger>
                        <TabsTrigger value="manual">⌨️ Code eingeben</TabsTrigger>
                    </TabsList>

                    <TabsContent value="scan">
                        <Card>
                            <CardContent className="pt-6">
                                <div
                                    id="qr-reader"
