                                )}
                            </CardContent>
                        </Card>
                    </TabsContent>

                    <TabsContent value="manual">
                        <Card>
                            <CardContent className="pt-6">
                                <form onSubmit={handleManualSubmit} className="space-y-4">
                                    <div>
                                        <p className="text-sm text-muted-foreground mb-3">
                                            Geben Sie den 6-stelligen Event-Code ein, der auf dem Bildschirm des Trainers angezeigt wird.
                                        </p>
                                        <Input
                                            value={manualCode}
                                            onChange={(e) => setManualCode(e.target.value.toUpperCase())}
                                            placeholder="z.B. TH-2026-A"
                                            className="text-center text-lg font-mono tracking-widest"
                                            maxLength={12}
                                        />
                                    </div>
                                    <Button type="submit" className="w-full" disabled={!manualCode.trim()}>
                                        Einchecken
                                    </Button>
                                </form>
                            </CardContent>
                        </Card>
                    </TabsContent>
                </Tabs>
            ) : (
                <motion.div
                    initial={{ scale: 0.9, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ type: "spring", duration: 0.5 }}
                >
                    <Card className="text-center border-brand-sky/30 bg-brand-sky/5">
                        <CardContent className="pt-10 pb-10">
                            <motion.div
                                initial={{ scale: 0 }}
                                animate={{ scale: 1 }}
                                transition={{ delay: 0.2, type: "spring", stiffness: 200 }}
                                className="text-7xl mb-6"
                            >
                                ✅
                            </motion.div>
                            <h2 className="text-brand-navy mb-2">Erfolgreich eingecheckt!</h2>
                            <p className="text-muted-foreground mb-4 max-w-sm mx-auto">
                                Sie nehmen am Live-Event teil. Der Trainer wird die erste Station in Kürze freischalten.
                            </p>
                            <Badge variant="secondary" className="text-sm px-4 py-1">
                                Event: {scanResult || manualCode}
                            </Badge>
                            <div className="mt-6 p-4 bg-muted rounded-xl max-w-sm mx-auto">
                                <p className="text-xs text-muted-foreground mb-2">Wartet auf Trainer…</p>
                                <div className="flex items-center justify-center gap-2">
                                    <div className="w-2 h-2 rounded-full bg-brand-sky animate-pulse"></div>
                                    <span className="text-sm font-bold text-brand-navy">Live-Verbindung aktiv</span>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </motion.div>
            )}

            {/* Info */}
            <Card>
                <CardHeader>
                    <CardTitle className="text-base">Wie funktioniert es?</CardTitle>
                </CardHeader>
                <CardContent className="space-y-3 text-sm text-muted-foreground">
                    <div className="flex gap-3">
                        <span className="text-lg">1️⃣</span>
                        <span>Der Trainer zeigt einen QR-Code auf dem Beamer oder gibt einen Event-Code durch.</span>
                    </div>
                    <div className="flex gap-3">
                        <span className="text-lg">2️⃣</span>
                        <span>Sie scannen den QR-Code mit Ihrer Kamera oder geben den Code manuell ein.</span>
                    </div>
                    <div className="flex gap-3">
                        <span className="text-lg">3️⃣</span>
                        <span>Sobald eingecheckt, werden Live-Aufgaben und Timer synchron auf Ihrem Gerät angezeigt.</span>
                    </div>
                </CardContent>
            </Card>
        </motion.div>
    );
}

"use client";

import { PremiumBackground } from "@/components/layout/premium-background";
import { useAuthStore } from "@/store/auth-store";
import { useUserStore } from "@/store/user-store";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { RoleGuard } from "@/components/auth/role-guard";
import { Settings as SettingsIcon, User, Bell, Palette, Shield, Globe, LogOut } from "lucide-react";
import { useTheme } from "next-themes";
import { useTranslations } from "next-intl";
import { motion } from "framer-motion";
import { useState } from "react";

export default function SettingsPage() {
    const { user, logout } = useAuthStore();
    const { theme, setTheme } = useTheme();
    const t = useTranslations("Navigation");

    const [notifyEvents, setNotifyEvents] = useState(true);
    const [notifyXp, setNotifyXp] = useState(true);

    const sections = [
        {
            id: "account",
            title: "Account & Profil",
            description: "Verwalten Sie Ihre persönlichen Informationen und Firmendaten.",
            icon: <User className="w-5 h-5 text-brand-sky" />,
            items: [
                { label: "Anzeigename", value: user?.name || "Gast", type: "text" },
                { label: "E-Mail Adresse", value: user?.email || "demo@thitronik.de", type: "text" },
                { label: "Firma", value: user?.company || "THITRONIK Partner", type: "text" }
            ]
        },
        {
            id: "appearance",
            title: "Erscheinungsbild",
            description: "Passen Sie das visuelle Design der App an Ihre Vorlieben an.",
            icon: <Palette className="w-5 h-5 text-brand-lime" />,
            content: (
                <div className="flex gap-4 mt-2">
                    {["light", "dark", "system"].map((m) => (
                        <Button
                            key={m}
                            variant="outline"
                            onClick={() => setTheme(m)}
                            className={`flex-1 capitalize border-white/10 text-white hover:bg-white/10 ${theme === m ? 'border-brand-sky bg-brand-sky/10 ring-1 ring-brand-sky/30' : ''}`}
                        >
                            {m === 'light' ? '☀️ ' : m === 'dark' ? '🌙 ' : '⚙️ '}{m}
                        </Button>
                    ))}
                </div>
            )
        },
        {
            id: "notifications",
            title: "Benachrichtigungen",
            description: "Wählen Sie, worüber Sie informiert werden möchten.",
            icon: <Bell className="w-5 h-5 text-yellow-400" />,
            content: (
                <div className="space-y-4 pt-2">
                    <div className="flex items-center justify-between p-4 border border-white/10 rounded-xl bg-white/5 gap-4">
                        <div className="space-y-1">
                            <p className="font-medium text-sm text-white">Event &amp; Check-in Reminder</p>
                            <p className="text-xs text-white/50">Infos zu anstehenden Workshops, Seminaren und Events auf dem Campus. Sie erhalten eine Erinnerung 24 Stunden vor Beginn.</p>
                        </div>
                        <Switch
                            checked={notifyEvents}
                            onCheckedChange={setNotifyEvents}
                            className="shrink-0"
                        />
                    </div>
                    <div className="flex items-center justify-between p-4 border border-white/10 rounded-xl bg-white/5 gap-4">
                        <div className="space-y-1">
                            <p className="font-medium text-sm text-white">XP &amp; Level Updates</p>
                            <p className="text-xs text-white/50">Visuelle Benachrichtigungen bei Gamification-Fortschritten – Level-Aufstiege, neue Abzeichen und XP-Gewinne.</p>
                        </div>
                        <Switch
                            checked={notifyXp}
                            onCheckedChange={setNotifyXp}
                            className="shrink-0"
                        />
                    </div>
                    <p className="text-xs text-white/30 pl-1">
                        ℹ️ Die Benachrichtigungen gelten nur für dieses Gerät und werden lokal gespeichert.
                    </p>
                </div>
            )
        },
        {
            id: "security",
            title: "Sicherheit",
            description: "Schützen Sie Ihren Account mit einem sicheren Passwort.",
            icon: <Shield className="w-5 h-5 text-brand-red" />,
            items: [
                { label: "Passwort ändern", value: "********", type: "password", button: "Ändern" }
            ]
        },
        {
            id: "language",
            title: "Sprache",
            description: "Wählen Sie Ihre bevorzugte Sprache für das Interface.",
            icon: <Globe className="w-5 h-5 text-brand-sky" />,
            content: (
                <div className="flex gap-4 mt-2">
                    <Button variant="outline" className="flex-1 border-brand-sky text-brand-sky bg-brand-sky/10">Deutsch</Button>
                    <Button variant="outline" className="flex-1 border-white/10 text-white hover:bg-white/10">English</Button>
                </div>
            )
        }
    ];


    return (
        <RoleGuard requiredRole="user">
            <PremiumBackground>
                <div className="max-w-4xl mx-auto py-8 px-4 md:px-8 space-y-8 animate-fade-in pb-20">
                    <header className="flex items-center justify-between group">
                        <div className="space-y-1">
                            <h1 className="text-4xl font-extrabold text-white flex items-center gap-4">
                                <SettingsIcon className="w-10 h-10 text-brand-lime animate-spin-slow group-hover:text-brand-sky transition-colors" />
                                Einstellungen
                            </h1>
                            <p className="text-white/60 text-lg">
                                Personalisieren Sie Ihr Campus-Erlebnis.
                            </p>
                        </div>
                        <Button 
                            variant="destructive" 
                            size="sm" 
                            className="bg-brand-red/20 hover:bg-brand-red text-white hover:text-white border-brand-red/30 transition-all font-bold gap-2"
                            onClick={() => logout()}
                        >
                            <LogOut className="w-4 h-4" /> Abmelden
                        </Button>
                    </header>

                    <div className="grid grid-cols-1 md:grid-cols-4 gap-8 h-full">
                        {/* Navigation Sidebar (Mobile Sticky) */}
                        <div className="md:col-span-1 space-y-2 hidden md:block h-fit sticky top-24">
                            {sections.map((s) => (
                                <a 
                                    key={s.id} 
                                    href={`#${s.id}`}
                                    className="flex items-center gap-3 p-3 rounded-xl hover:bg-white/10 text-white/70 hover:text-white transition-all group"
                                >
                                    <span className="group-hover:scale-110 transition-transform">{s.icon}</span>
                                    <span className="font-medium">{s.title.split(' ')[0]}</span>
                                </a>
                            ))}
                        </div>

                        {/* Content Area */}
                        <div className="md:col-span-3 space-y-8">
                            {sections.map((section, idx) => (
                                <motion.div
                                    key={section.id}
                                    id={section.id}
                                    initial={{ opacity: 0, x: 20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: idx * 0.1 }}
                                >
                                    <Card className="bg-white/10 border-white/20 backdrop-blur-md shadow-xl overflow-hidden group">
                                        <CardHeader className="border-b border-white/10">
                                            <div className="flex items-center gap-3 mb-2">
                                                <div className="p-2 bg-white/5 rounded-lg group-hover:bg-white/10 transition-colors">
                                                    {section.icon}
                                                </div>
                                                <CardTitle className="text-white text-xl">{section.title}</CardTitle>
                                            </div>
                                            <CardDescription className="text-white/60">
                                                {section.description}
                                            </CardDescription>
                                        </CardHeader>
                                        <CardContent className="pt-6">
                                            {section.items ? (
                                                <div className="space-y-6">
                                                    {section.items.map((item, i) => (
                                                        <div key={i} className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                                            <Label className="text-white/50 font-medium sm:w-1/3 italic">{item.label}</Label>
                                                            <div className="flex-1 flex items-center justify-between gap-4 p-2 bg-white/5 rounded-lg border border-white/5">
                                                                <span className="text-white font-medium">{item.value}</span>
                                                                {(item as any).button && (
                                                                    <Button size="sm" variant="ghost" className="text-brand-sky hover:text-white hover:bg-brand-sky/20">
                                                                        {(item as any).button}
                                                                    </Button>
                                                                )}
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            ) : section.content}
                                        </CardContent>
                                    </Card>
                                </motion.div>
                            ))}

                            {/* Info Card */}
                            <motion.div
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                transition={{ delay: 0.6 }}
                                className="p-6 bg-brand-navy border border-white/10 rounded-2xl text-center relative overflow-hidden"
                            >
                                <p className="text-white/40 text-xs">
                                    THITRONIK Campus v2.4.0 • Build 2026-03-12
                                </p>
                            </motion.div>
                        </div>
                    </div>
                </div>
            </PremiumBackground>
        </RoleGuard>
    );
}

