function readFileAsDataUrl(file: File) {
    return new Promise<string>((resolve, reject) => {
        const reader = new FileReader()
        reader.onload = (e) => resolve(String(e.target?.result || ""))
        reader.onerror = reject
        reader.readAsDataURL(file)
    })
}

