                                                            className="h-10 px-4 rounded-xl"
                                                            style={{ backgroundColor: TH.navyLight, color: TH.white }}
                                                        >
                                                            <Send className="w-3.5 h-3.5" />
                                                        </Button>
                                                    </div>
                                                )}
                                            </div>
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </motion.div>
                        );
                    })}
                </AnimatePresence>
                <div ref={bottomRef} />
            </div>
        </div>
    );
}

