                            : <><span className="text-brand-sky font-bold">{next.icon} {next.title}</span>
                                {next.loc && next.loc !== '–' && ` · ${next.loc}, ${next.bldg}`}
                                {' · ab '}<span className="font-mono font-bold">{fmt(next.s)}</span></>
                        }
                    </div>
                </div>
            )}
        </Card>
    );
}

