import { Check, X, Star, RotateCcw, ArrowRight, Clock, Trophy, Puzzle, AlertCircle, Search } from "lucide-react"

import { fillTheGapQuestions, FillTheGapQuestion } from "@/data/fill-the-gap-questions"

type GameState = "setup" | "playing" | "review" | "finished"
type Category = "produkte" | "einbau" | "alarmsysteme" | "allgemein" | "alle"
type Difficulty = "leicht" | "mittel" | "schwer"

interface AnswerRecord {
  questionId: string
  userAnswer: string
  isCorrect: boolean
  timeTakenMs: number
}

// Fisher-Yates shuffle
function shuffle<T>(array: T[]): T[] {
  const result = [...array]
  for (let i = result.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[result[i], result[j]] = [result[j], result[i]]
  }
  return result
}

export default function FillTheGapGame({ onFinished }: { onFinished?: (score: number) => void }) {
  const [gameState, setGameState] = useState<GameState>("setup")

  // Setup state
  const [selectedCategory, setSelectedCategory] = useState<Category>("alle")
  const [selectedDifficulty, setSelectedDifficulty] = useState<Difficulty>("leicht")
  const [questionCount, setQuestionCount] = useState<number>(5)

  // Play state
  const [questions, setQuestions] = useState<FillTheGapQuestion[]>([])
  const [currentIndex, setCurrentIndex] = useState(0)
  const [userAnswer, setUserAnswer] = useState("")
  const [isAnswered, setIsAnswered] = useState(false)
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null)
  const [answers, setAnswers] = useState<AnswerRecord[]>([])
  const [questionStartTime, setQuestionStartTime] = useState<number>(0)
  const [elapsedTimeMs, setElapsedTimeMs] = useState(0)

  const inputRef = useRef<HTMLInputElement>(null)

  // Start the game
  const startGame = () => {
    let filtered = fillTheGapQuestions
    if (selectedCategory !== "alle") {
      filtered = filtered.filter((q) => q.category === selectedCategory || q.category === "allgemein") // Always include allgemein as fallback if needed
    }
    // ensure exact category matches first, then fill up if needed
    let exactMatches = fillTheGapQuestions.filter((q) => selectedCategory === "alle" || q.category === selectedCategory)

    if (exactMatches.length < questionCount) {
       exactMatches = [...exactMatches, ...fillTheGapQuestions.filter(q => q.category !== selectedCategory)]
    }

    const shuffled = shuffle(exactMatches).slice(0, questionCount)
    setQuestions(shuffled)
    setCurrentIndex(0)
    setAnswers([])
    setUserAnswer("")
    setIsAnswered(false)
    setIsCorrect(null)
    setGameState("playing")
    setQuestionStartTime(performance.now())
    setElapsedTimeMs(0)
  }

  const handleNextQuestion = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex((prev) => prev + 1)
      setUserAnswer("")
      setIsAnswered(false)
      setIsCorrect(null)
      setQuestionStartTime(performance.now())
    } else {
      setGameState("review")
    }
  }

  const checkAnswer = (answerOverride?: string) => {
    if (isAnswered) return

    const currentQuestion = questions[currentIndex]
    const finalAnswer = answerOverride ?? userAnswer
    const finalTrimmed = finalAnswer.trim().toLowerCase()

    const isOkContext = finalTrimmed === currentQuestion.answer.toLowerCase() || 
                       (currentQuestion.acceptedAlternatives && currentQuestion.acceptedAlternatives.some(a => a.toLowerCase() === finalTrimmed))

    const timeTaken = performance.now() - questionStartTime

    setIsCorrect(!!isOkContext)
    setIsAnswered(true)

    // Play sound feedback placeholder
    try {
        const audio = new Audio(isOkContext ? "/sounds/success.mp3" : "/sounds/error.mp3")
        // we won't actually play anything because files aren't there but we follow the prompt 
        // audio.play().catch(() => {})
    } catch {}

    setAnswers(prev => [...prev, {
      questionId: currentQuestion.id,
      userAnswer: finalAnswer,
      isCorrect: !!isOkContext,
      timeTakenMs: timeTaken
    }])

    setTimeout(() => {
      handleNextQuestion()
    }, 1500)
  }

  // Effect for timer
  useEffect(() => {
    if (gameState === "playing" && !isAnswered) {
      let animationFrameId: number
      const start = performance.now()

      const updateTimer = () => {
        setElapsedTimeMs(performance.now() - questionStartTime)
        animationFrameId = requestAnimationFrame(updateTimer)
      }
      animationFrameId = requestAnimationFrame(updateTimer)
      return () => cancelAnimationFrame(animationFrameId)
    }
  }, [gameState, isAnswered, questionStartTime])

  // Derived State (moved to top level to obey rules of hooks)
  const currentQ = questions[currentIndex]

  const displayOptions = useMemo(() => {
     if (gameState !== "playing" || !currentQ || selectedDifficulty === "schwer") return []

     let opts = [...currentQ.options]
     if (!opts.includes(currentQ.answer)) opts.push(currentQ.answer)
     opts = shuffle(opts)

     let finalOpts = []
     if (selectedDifficulty === "leicht") finalOpts = opts.slice(0, 3)
     else finalOpts = opts.slice(0, 5)

     // ensure correct answer is always in options!
     if (!finalOpts.includes(currentQ.answer)) {
         finalOpts[0] = currentQ.answer
         finalOpts = shuffle(finalOpts)
     }
     return finalOpts
  }, [currentIndex, currentQ?.id, selectedDifficulty, gameState])

  const hasCalledFinishedRef = useRef(false)
  useEffect(() => {
    if (gameState === "setup" || gameState === "playing") {
      hasCalledFinishedRef.current = false
    }
    if (gameState === "finished" && !hasCalledFinishedRef.current && onFinished) {
      const correctCount = answers.filter(a => a.isCorrect).length
      onFinished(correctCount * 10)
      hasCalledFinishedRef.current = true
    }
  }, [gameState, answers, onFinished])

  // Setup View
  if (gameState === "setup") {
    return (
      <Card className="bg-white/10 border-white/20 backdrop-blur-md text-white">
        <CardHeader>
          <CardTitle className="text-2xl flex items-center gap-2">
            <Puzzle className="w-6 h-6 text-brand-lime" /> Setup Lückentext
          </CardTitle>
          <CardDescription className="text-white/60">
            Wähle dein Thema und den Schwierigkeitsgrad.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-3">
            <label className="text-sm font-medium">Kategorie</label>
            <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
              {["alle", "produkte", "einbau", "alarmsysteme", "allgemein"].map((cat) => (
                <Button
                  key={cat}
                  variant={selectedCategory === cat ? "default" : "outline"}
                  onClick={() => setSelectedCategory(cat as Category)}
                  className={selectedCategory === cat ? "bg-brand-lime text-brand-navy hover:bg-brand-lime/90 border-transparent" : "border-white/20 text-white hover:bg-white/10"}
                >
                  {cat.charAt(0).toUpperCase() + cat.slice(1)}
                </Button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            <label className="text-sm font-medium">Schwierigkeitsgrad</label>
            <div className="grid grid-cols-3 gap-2">
              {[
                { id: "leicht", label: "Leicht", desc: "Multiple-Choice (3)" },
                { id: "mittel", label: "Mittel", desc: "Multiple-Choice (5)" },
                { id: "schwer", label: "Schwer", desc: "Freitext" },
              ].map((diff) => (
                <Button
                  key={diff.id}
                  variant={selectedDifficulty === diff.id ? "default" : "outline"}
                  onClick={() => setSelectedDifficulty(diff.id as Difficulty)}
                  className={`flex flex-col h-auto py-3 px-2 ${selectedDifficulty === diff.id ? 'bg-brand-lime text-brand-navy hover:bg-brand-lime/90 border-transparent' : 'border-white/20 text-white hover:bg-white/10'}`}
                >
                  <span className="font-bold">{diff.label}</span>
                  <span className="text-xs opacity-70 mt-1">{diff.desc}</span>
                </Button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            <label className="text-sm font-medium">Anzahl Fragen</label>
            <div className="grid grid-cols-3 gap-2">
              {[5, 10, 15].map((num) => (
                <Button
                  key={num}
                  variant={questionCount === num ? "default" : "outline"}
                  onClick={() => setQuestionCount(num)}
                  className={questionCount === num ? "bg-brand-lime text-brand-navy hover:bg-brand-lime/90 border-transparent" : "border-white/20 text-white hover:bg-white/10"}
                >
                  {num}
                </Button>
              ))}
            </div>
          </div>
        </CardContent>
        <CardFooter>
          <Button onClick={startGame} className="w-full bg-brand-lime text-brand-navy hover:bg-brand-lime/90 font-bold gap-2 text-lg py-6">
            <Check className="w-5 h-5" /> Spiel starten
          </Button>
        </CardFooter>
      </Card>
    )
  }

  // Playing View
  if (gameState === "playing" && questions.length > 0) {
    const progress = ((currentIndex) / questions.length) * 100
    const sentenceParts = currentQ.sentence.split("{{gap}}")

    return (
      <motion.div
        key={`question-${currentIndex}`}
        initial={{ opacity: 0, x: 50 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, x: -50 }}
        className="space-y-6"
      >
        <div className="flex justify-between items-center text-white/80">
           <span className="font-bold">Frage {currentIndex + 1} / {questions.length}</span>
           <span className="flex items-center gap-1 font-mono"><Clock className="w-4 h-4"/> {Math.floor(elapsedTimeMs / 1000)}s</span>
        </div>
        <Progress value={progress} className="h-3 bg-white/10" />

        <Card className="bg-white/10 border-white/20 backdrop-blur-md text-white">
          <CardContent className="pt-10 pb-10 text-center relative">
            <p className="text-xl md:text-2xl font-medium leading-relaxed">
              {sentenceParts[0]}
              {selectedDifficulty === "schwer" ? (
                 <span className="inline-block mx-2 relative">
                   <Input
                     ref={inputRef}
                     value={userAnswer}
                     onChange={(e) => setUserAnswer(e.target.value)}
                     disabled={isAnswered}
                     className={`w-36 md:w-48 inline-block text-center border-b-2 border-t-0 border-l-0 border-r-0 rounded-none bg-transparent focus-visible:ring-0 px-1 text-brand-lime placeholder:text-white/30 font-bold ${isAnswered ? (isCorrect ? 'text-green-400 border-green-400' : 'text-red-400 border-red-400') : 'border-white/40 focus:border-brand-lime'}`}
                     placeholder="..."
                     onKeyDown={(e) => {
                       if (e.key === "Enter" && userAnswer.trim().length > 0) {
                         checkAnswer()
                       }
                     }}
                     autoFocus
                   />
                 </span>
              ) : (
                <span className={`inline-block mx-2 min-w-[100px] border-b-2 border-dashed px-2 pb-1 ${isAnswered ? 'border-transparent' : 'border-white/40 animate-pulse'}`}>
                   {isAnswered ? (
                      <Badge variant="outline" className={`text-lg px-3 py-1 ${isCorrect ? 'bg-green-500/20 border-green-500 text-green-300' : 'bg-red-500/20 border-red-500 text-red-300'}`}>
                         {userAnswer || "?"}
                      </Badge>
                   ) : userAnswer ? (
                      <Badge variant="outline" className="text-lg px-3 py-1 bg-white/10 text-white border-white/40">
                        {userAnswer}
                      </Badge>
                   ) : (
                      <span className="text-transparent">____</span>
                   )}
                </span>
              )}
              {sentenceParts[1]}
            </p>

            <AnimatePresence>
                {isAnswered && (
                  <motion.div
                    initial={{ scale: 0, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    className="absolute bottom-4 right-4"
                  >
                    {isCorrect ? (
                       <div className="w-12 h-12 bg-green-500 rounded-full flex items-center justify-center shadow-lg shadow-green-500/50">
                         <Check className="w-6 h-6 text-white" />
                       </div>
                    ) : (
                       <div className="w-12 h-12 bg-red-500 rounded-full flex items-center justify-center shadow-lg shadow-red-500/50">
                         <X className="w-6 h-6 text-white" />
                       </div>
                    )}
                  </motion.div>
                )}
            </AnimatePresence>
          </CardContent>

          <CardFooter className="flex-col gap-4 bg-white/5 rounded-b-xl">
             {selectedDifficulty !== "schwer" ? (
                 <div className="w-full grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3">
                   {displayOptions.map((opt, i) => {
                     let btnClass = "border-white/20 text-white hover:bg-white/10"
                     if (isAnswered) {
                         if (opt === currentQ.answer) btnClass = "bg-green-500/20 border-green-500 text-green-300 hover:bg-green-500/30"
                         else if (opt === userAnswer) btnClass = "bg-red-500/20 border-red-500 text-red-300 hover:bg-red-500/30"
                         else btnClass = "opacity-50 border-white/10 text-white/50"
                     } else if (opt === userAnswer) {
                         btnClass = "bg-white/20 border-white text-white"
                     }
                     return (
                       <Button
                         key={i}
                         variant="outline"
                         disabled={isAnswered}
                         className={`w-full h-auto py-3 whitespace-normal ${btnClass}`}
                         onClick={() => {
                             setUserAnswer(opt)
                             checkAnswer(opt)
                         }}
                       >
                         {opt}
                       </Button>
                     )
                   })}
                 </div>
             ) : (
                <div className="w-full flex justify-end">
                   <Button 
                     onClick={() => checkAnswer()} 
                     disabled={isAnswered || !userAnswer.trim()}
                     className="bg-brand-lime text-brand-navy hover:bg-brand-lime/90 font-bold"
                   >
                      Prüfen
                   </Button>
                </div>
             )}

             {isAnswered && !isCorrect && selectedDifficulty === "schwer" && (
                <motion.div 
                   initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                   className="w-full p-3 rounded-lg bg-red-500/10 border border-red-500/30 text-red-200 text-sm mt-2 flex items-start gap-2"
                >
                   <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
                   <div>
                     <p className="font-bold">Richtige Antwort:</p>
                     <p>{currentQ.answer}</p>
                   </div>
                </motion.div>
             )}
          </CardFooter>
        </Card>
      </motion.div>
    )
  }

  // Review View
  if (gameState === "review") {
    return (
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="space-y-6"
      >
        <div className="flex justify-between items-center text-white">
          <h2 className="text-2xl font-bold flex items-center gap-2">
            <Search className="w-6 h-6 text-brand-lime" /> Review
          </h2>
          <Button onClick={() => setGameState("finished")} className="bg-brand-lime text-brand-navy font-bold hover:bg-brand-lime/90 gap-2">
             Weiter zum Ergebnis <ArrowRight className="w-4 h-4" />
          </Button>
        </div>

        <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
           {answers.map((ans, idx) => {
              const q = questions.find(q => q.id === ans.questionId)!
              const sentenceParts = q.sentence.split("{{gap}}")
              return (
                 <Card key={idx} className={`bg-white/10 border backdrop-blur-sm ${ans.isCorrect ? 'border-green-500/30' : 'border-red-500/30'}`}>
                    <CardContent className="p-4 space-y-3 text-white">
                      <div className="flex items-start gap-3">
                         <div className={`mt-1 shrink-0 w-6 h-6 rounded-full flex items-center justify-center ${ans.isCorrect ? 'bg-green-500' : 'bg-red-500'}`}>
                           {ans.isCorrect ? <Check className="w-4 h-4 text-white"/> : <X className="w-4 h-4 text-white"/>}
                         </div>
                         <div>
                           <p className="opacity-80 text-sm mb-1">Frage {idx + 1}</p>
                           <p className="font-medium">
                             {sentenceParts[0]}
                             <span className={`inline-block px-1 mx-1 font-bold border-b-2 ${ans.isCorrect ? 'text-green-400 border-green-400' : 'text-red-400 border-red-400 line-through'}`}>
                                {ans.userAnswer || "(Keine Antwort)"}
                             </span>
                             {sentenceParts[1]}
                           </p>
                           {!ans.isCorrect && (
                              <p className="text-green-400 font-bold mt-2 text-sm flex items-center gap-1">
                                <ArrowRight className="w-3 h-3"/> Korrekt: {q.answer}
                              </p>
                           )}
                           {q.explanation && (
                              <p className="text-white/60 text-sm mt-2 italic flex items-start gap-1">
                                <AlertCircle className="w-3 h-3 shrink-0 mt-0.5" />
                                {q.explanation}
                              </p>
                           )}
                         </div>
                      </div>
                    </CardContent>
                 </Card>
              )
           })}
        </div>
      </motion.div>
    )
  }

  // Finished View
  if (gameState === "finished") {
    const correctCount = answers.filter(a => a.isCorrect).length
    const accuracy = Math.round((correctCount / questions.length) * 100)

    let stars = 1
    if (accuracy >= 80) stars = 3
    else if (accuracy >= 50) stars = 2

    const totalTime = answers.reduce((acc, curr) => acc + curr.timeTakenMs, 0)
    const avgTime = Math.round(totalTime / questions.length / 1000)

    return (
      <motion.div
         initial={{ opacity: 0, y: 20 }}
         animate={{ opacity: 1, y: 0 }}
      >
        <Card className="bg-white/10 border-white/20 backdrop-blur-md text-white overflow-hidden">
           <div className="bg-gradient-to-r from-brand-navy/60 to-brand-navy/30 pt-10 pb-6 text-center shadow-inner relative">
              <Trophy className="w-16 h-16 text-brand-lime mx-auto mb-4 opacity-20 absolute top-4 right-4" />
              <h2 className="text-3xl font-bold mb-2">Ergebnis</h2>

              <div className="flex justify-center gap-2 mb-6">
                {[1, 2, 3].map((starIdx) => (
                   <motion.div
                     key={starIdx}
                     initial={{ scale: 0 }}
                     animate={{ scale: 1 }}
                     transition={{ delay: 0.3 + (starIdx * 0.2), type: "spring" }}
                   >
                     <Star className={`w-12 h-12 ${starIdx <= stars ? 'text-yellow-400 fill-yellow-400' : 'text-white/20'}`} />
                   </motion.div>
                ))}
              </div>

              <p className="text-5xl font-black text-brand-lime tracking-tight">
                 {correctCount} <span className="text-2xl text-white/50 font-medium">/ {questions.length}</span>
              </p>
           </div>

           <CardContent className="grid grid-cols-2 gap-4 p-6">
              <div className="bg-white/5 rounded-xl p-4 text-center">
                 <p className="text-white/60 text-sm mb-1">Genauigkeit</p>
                 <p className="text-2xl font-bold">{accuracy}%</p>
              </div>
              <div className="bg-white/5 rounded-xl p-4 text-center">
                 <p className="text-white/60 text-sm mb-1">Ø Zeit pro Frage</p>
                 <p className="text-2xl font-bold">{avgTime}s</p>
              </div>
           </CardContent>
           <CardFooter className="flex flex-col gap-3 p-6 pt-0">
              <Button onClick={() => startGame()} className="w-full bg-brand-lime text-brand-navy font-bold gap-2">
                 <RotateCcw className="w-4 h-4"/> Nochmal spielen
              </Button>
              <Button onClick={() => setGameState("setup")} variant="outline" className="w-full border-white/20 text-white hover:bg-white/10">
                 Andere Einstellungen
              </Button>
           </CardFooter>
        </Card>
      </motion.div>
    )
  }

  return null
}

"use client";

import { useState } from "react";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useUserStore } from "@/store/user-store";

export function DailyChallenge() {
    const [isAnswered, setIsAnswered] = useState(false);
    const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
    const addXp = useUserStore((state) => state.addXp);

    const handleAnswer = (correct: boolean) => {
        setIsAnswered(true);
        setIsCorrect(correct);
        if (correct) {
            // Direct store update + trigger popup event for visual consistency
            addXp(25);
            window.dispatchEvent(
                new CustomEvent("add-xp", {
                    detail: { amount: 25, reason: "Daily Challenge gemeistert" },
                })
            );
        }
    };

    return (
        <Card className="bg-gradient-to-br from-brand-navy to-brand-navy/95 text-white border-none relative overflow-hidden shadow-md">
            {/* Decorative Background Elements */}
            <div className="absolute -top-10 -right-10 w-32 h-32 bg-white/10 rounded-full blur-2xl pointer-events-none"></div>
            <div className="absolute -bottom-6 -left-6 w-24 h-24 bg-brand-lime/20 rounded-full blur-xl pointer-events-none"></div>

            <div className="relative z-10 p-5 md:p-6">
                <div className="flex justify-between items-start mb-5">
                    <div className="flex items-center gap-2.5">
                        <span className="text-3xl drop-shadow-sm">⚡</span>
                        <h3 className="font-bold text-lg md:text-xl">Daily Challenge</h3>
                    </div>
                    <Badge className="bg-white/20 hover:bg-white/30 text-white border-none px-3 py-1 font-bold">
                        +25 XP
                    </Badge>
                </div>

                {!isAnswered ? (
                    <div className="animate-fade-in">
                        <p className="text-white/90 text-sm md:text-base mb-5 leading-relaxed font-medium">
                            Welche Aussage zum Einbau der WiPro III ist KORREKT?
                        </p>
                        <div className="space-y-3">
                            <button
                                onClick={() => handleAnswer(false)}
                                className="w-full text-left p-3.5 rounded-xl bg-white/10 hover:bg-white/20 border border-white/20 transition-all text-sm text-white/90 font-medium"
                            >
                                A) Das NFC-Modul muss ausserhalb des Fahrzeugs (z.B. am Spiegel) montiert werden.
                            </button>
                            <button
                                onClick={() => handleAnswer(true)}
                                className="w-full text-left p-3.5 rounded-xl bg-white/10 hover:bg-white/20 border border-white/20 transition-all text-sm text-white/90 font-medium"
                            >
                                B) Das NFC-Modul kann unsichtbar hinter GFK, Holz oder Kunststoff verbaut werden.
                            </button>
                            <button
                                onClick={() => handleAnswer(false)}
                                className="w-full text-left p-3.5 rounded-xl bg-white/10 hover:bg-white/20 border border-white/20 transition-all text-sm text-white/90 font-medium"
                            >
                                C) NFC funktioniert nur bei metallischen Außenwänden zuverlässig.
                            </button>
                        </div>
                    </div>
                ) : (
                    <div className="animate-fade-in py-4 text-center">
                        <div className={`text-6xl mb-4 ${isCorrect ? "text-brand-lime drop-shadow-md" : "text-brand-red opacity-80"}`}>
                            {isCorrect ? "🎉" : "💡"}
                        </div>
                        <h4 className="font-bold text-2xl mb-3">
                            {isCorrect ? "Perfekt!" : "Knapp daneben."}
                        </h4>
                        <p className="text-sm md:text-base text-white/80 mb-6 leading-relaxed max-w-xs mx-auto">
                            Das NFC-Pad funkt problemlos durch Kunststoff, Holz oder GFK bis ca. 10mm Stärke. Es darf NICHT auf oder hinter Blech montiert werden.
                        </p>
                        {isCorrect ? (
                            <span className="inline-block bg-brand-lime text-brand-navy font-extrabold px-5 py-2.5 rounded-full text-sm shadow-lg animate-bounce">
                                +25 XP gesichert
                            </span>
                        ) : (
                            <span className="inline-block bg-white/15 text-white/90 font-bold px-5 py-2.5 rounded-full text-sm">
                                Morgen gibt's eine neue Chance!
                            </span>
                        )}
                    </div>
                )}
            </div>
        </Card>
    );
}

"use client";

import { useState } from "react";
import { useUserStore } from "@/store/user-store";
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Check, X, AlertTriangle } from "lucide-react";

type ConfigState = {
    vehicle: string;
    centralUnit: string;
    accessories: string[];
};

export function ConfiguratorSimulator() {
    const { addXp } = useUserStore();

    const [config, setConfig] = useState<ConfigState>({
        vehicle: '',
        centralUnit: '',
        accessories: [],
    });

    const [feedback, setFeedback] = useState<{ message: string; isError: boolean } | null>(null);
    const [isCompleted, setIsCompleted] = useState(false);

    // Aufgabe
    const GOAL = {
        vehicle: 'kastenwagen',
        centralUnit: 'wipro3',
        requiredAccessories: ['nfc', 'gaswarner'],
    };

    const toggleAccessory = (accId: string) => {
        setConfig(prev => ({
            ...prev,
            accessories: prev.accessories.includes(accId)
                ? prev.accessories.filter(a => a !== accId)
                : [...prev.accessories, accId]
        }));
    };

    const validateConfiguration = () => {
        if (!config.vehicle) {
            setFeedback({ message: 'Bitte wählen Sie zuerst ein Basisfahrzeug aus.', isError: true });
            return;
        }
        if (!config.centralUnit) {
            setFeedback({ message: 'Bitte wählen Sie eine Zentrale (Alarmanlage) aus.', isError: true });
            return;
        }

        // Spezifische Fehler-Szenarien für Lerneffekt
        if (config.vehicle === 'integriert' && config.accessories.includes('magnetkontakte') && config.accessories.length === 1) {
            setFeedback({ message: 'Achtung: Bei integrierten Wohnmobilen gibt es oft mehr als 2 Aufbautüren. Prüfen Sie die Anzahl der benötigten Magnetkontakte genau.', isError: true });
            return;
        }

        // Check gegen das Ziel
        if (config.vehicle !== GOAL.vehicle) {
            setFeedback({ message: 'Das gewählte Fahrzeug passt nicht zur Kundenanforderung (Kastenwagen).', isError: true });
            return;
        }
        if (config.centralUnit !== GOAL.centralUnit) {
            setFeedback({ message: 'Für diesen Kunden wurde eine WiPro III angefragt.', isError: true });
            return;
        }

        const missingAccessories = GOAL.requiredAccessories.filter(req => !config.accessories.includes(req));
        if (missingAccessories.length > 0) {
            setFeedback({ message: `Die Konfiguration ist noch unvollständig. Der Kunde wollte auch: Gaswarner und NFC.`, isError: true });
            return;
        }

        // Success
        setFeedback({ message: 'Perfekt konfiguriert! Die Anlage deckt alle Kundenwünsche ab und passt zum Fahrzeugtyp.', isError: false });
        if (!isCompleted) {
            setIsCompleted(true);
            addXp(150); // Nutze den Global Gamer Store
        }
    };

    return (
        <Card className="max-w-4xl mx-auto border-border shadow-md animate-fade-in mt-6">
            <CardHeader className="flex flex-col md:flex-row justify-between items-start md:items-center border-b border-border pb-6 bg-muted/20">
                <div>
                    <CardTitle className="text-xl flex items-center gap-2 text-brand-navy mb-1">
                        <span className="text-2xl">⚙️</span> THITRONIK Konfigurator Simulator
                    </CardTitle>
                    <CardDescription>Übungs-Szenario: Konfiguration für Neukunden erstellen</CardDescription>
                </div>
                <div className="text-right flex flex-col items-end gap-2 mt-4 md:mt-0 max-w-sm">
                    <Badge variant="secondary" className="mb-1 text-xs">Aktuelle Aufgabe</Badge>
                    <div className="text-sm text-left bg-background p-3 rounded-lg border border-border italic text-muted-foreground shadow-sm">
                        <strong className="block text-foreground not-italic mb-1 text-xs">Kundenanforderung:</strong>
                        "Ich habe einen neuen Ducato Kastenwagen und hätte dafür gerne die WiPro III. Meine Frau möchte das per Smartphone entsperren können (NFC) und wir brauchen zwingend einen Gaswarner."
                    </div>
                </div>
            </CardHeader>

            <CardContent className="p-6 grid grid-cols-1 md:grid-cols-5 gap-8">
                {/* Left Col: Configurator Form */}
                <div className="md:col-span-3 space-y-8">

                    {/* Fahrzeug */}
                    <div>
                        <h3 className="text-xs font-bold text-muted-foreground mb-3 uppercase tracking-wider">1. Basisfahrzeug</h3>
                        <div className="grid grid-cols-2 gap-3">
                            {[
                                { id: 'kastenwagen', label: 'Kastenwagen (z.B. Ducato)' },
                                { id: 'teilintegriert', label: 'Teilintegriert' },
                                { id: 'integriert', label: 'Vollintegriert' },
                                { id: 'alkoven', label: 'Alkoven' }
                            ].map(v => (
                                <button
                                    key={v.id}
                                    onClick={() => setConfig(prev => ({ ...prev, vehicle: v.id }))}
                                    className={`p-3 rounded-xl border text-sm text-left transition-all ${config.vehicle === v.id ? 'border-brand-sky bg-brand-sky/10 font-bold text-brand-sky shadow-sm' : 'border-border hover:border-brand-sky/50 bg-background cursor-pointer'}`}
                                >
                                    {v.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Zentrale */}
                    <div>
                        <h3 className="text-xs font-bold text-muted-foreground mb-3 uppercase tracking-wider">2. Alarmsystem</h3>
                        <div className="grid grid-cols-2 gap-3">
                            {[
                                { id: 'wipro3', label: 'WiPro III (CAN-Bus)' },
                                { id: 'cas', label: 'C.A.S. III (Analog)' }
                            ].map(c => (
                                <button
                                    key={c.id}
                                    onClick={() => setConfig(prev => ({ ...prev, centralUnit: c.id }))}
                                    className={`p-3 rounded-xl border text-sm text-left transition-all ${config.centralUnit === c.id ? 'border-brand-sky bg-brand-sky/10 font-bold text-brand-sky shadow-sm' : 'border-border hover:border-brand-sky/50 bg-background cursor-pointer'}`}
                                >
                                    {c.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Zubehör */}
                    <div>
                        <h3 className="text-xs font-bold text-muted-foreground mb-3 uppercase tracking-wider">3. Funk-Zubehör</h3>
                        <div className="space-y-2">
                            {[
                                { id: 'magnetkontakte', label: 'Funk-Magnetkontakte', desc: 'Sichert Fenster & Türen' },
                                { id: 'gaswarner', label: 'Funk-Gaswarner', desc: 'Narkosegas, Propan/Butan' },
                                { id: 'profinder', label: 'Pro-finder', desc: 'GPS-Ortung & Alarm-SMS' },
                                { id: 'nfc', label: 'NFC-Modul', desc: 'Entschärfen via Smartphone' },
                                { id: 'kabelschleife', label: 'Funk-Kabelschleife', desc: 'Sichert Fahrräder & Möbel' }
                            ].map(acc => (
                                <label key={acc.id} className={`flex items-start gap-3 p-3 rounded-xl border cursor-pointer transition-all ${config.accessories.includes(acc.id) ? 'border-brand-sky bg-brand-sky/5' : 'border-border hover:border-brand-sky/40 bg-background'}`}>
                                    <input
                                        type="checkbox"
                                        className="mt-1 accent-brand-sky w-4 h-4 rounded-sm border-brand-sky text-brand-sky focus:ring-brand-sky"
                                        checked={config.accessories.includes(acc.id)}
                                        onChange={() => toggleAccessory(acc.id)}
                                    />
                                    <div>
                                        <span className={`block font-bold text-sm leading-none mb-1 ${config.accessories.includes(acc.id) ? 'text-brand-sky' : 'text-foreground'}`}>{acc.label}</span>
                                        <span className="block text-xs text-muted-foreground leading-tight">{acc.desc}</span>
                                    </div>
                                </label>
                            ))}
                        </div>
                    </div>

                    <Button onClick={validateConfiguration} className="w-full bg-brand-navy hover:bg-brand-navy/90 text-white shadow-md text-lg py-6" disabled={isCompleted}>
                        Kunden-Konfiguration prüfen
                    </Button>

                </div>

                {/* Right Col: Summary & Validation Feedback */}
                <div className="md:col-span-2 bg-muted/30 p-5 rounded-2xl border border-border flex flex-col h-fit sticky top-6">
                    <h3 className="text-lg font-bold text-foreground mb-4 border-b border-border pb-2">Ihre Konfiguration</h3>

                    <ul className="space-y-3 mb-8 flex-1">
                        <li className="flex justify-between items-center text-sm border-b border-border/50 pb-2">
                            <span className="text-muted-foreground">Fahrzeug:</span>
                            <span className="font-bold text-foreground capitalize">{config.vehicle || '-'}</span>
                        </li>
                        <li className="flex justify-between items-center text-sm border-b border-border/50 pb-2">
                            <span className="text-muted-foreground">Zentrale:</span>
                            <span className="font-bold text-foreground">{config.centralUnit === 'wipro3' ? 'WiPro III' : config.centralUnit === 'cas' ? 'C.A.S. III' : '-'}</span>
                        </li>
                        <li className="text-sm pt-2">
                            <span className="block text-muted-foreground mb-2">Zubehör ({config.accessories.length}):</span>
                            {config.accessories.length > 0 ? (
                                <div className="flex flex-wrap gap-2">
                                    {config.accessories.map(a => (
                                        <span key={a} className="bg-background border border-border px-2 py-1 rounded-md text-xs font-medium text-foreground capitalize">{a}</span>
                                    ))}
                                </div>
                            ) : (
                                <span className="text-xs text-muted-foreground italic">Kein Zubehör gewählt</span>
                            )}
                        </li>
                    </ul>

                    {/* Validation Box */}
                    {feedback && (
                        <div className={`p-4 rounded-xl shadow-sm border ${feedback.isError ? 'bg-destructive/5 border-destructive/20' : 'bg-brand-lime/10 border-brand-lime/30'} animate-in fade-in slide-in-from-bottom-2`}>
                            <div className="flex gap-3 items-start">
                                {feedback.isError ? <AlertTriangle className="h-5 w-5 text-destructive shrink-0 mt-0.5" /> : <Check className="h-5 w-5 text-brand-lime shrink-0 mt-0.5" />}
                                <div>
                                    <h4 className={`font-bold mb-1 text-sm ${feedback.isError ? 'text-destructive' : 'text-brand-lime'}`}>
                                        {feedback.isError ? 'Feedback vom Ausbilder' : 'Ausgezeichnet!'}
                                    </h4>
                                    <p className={`text-xs ${feedback.isError ? 'text-foreground' : 'text-foreground/90'}`}>{feedback.message}</p>
                                </div>
                            </div>

                            {!feedback.isError && (
                                <div className="mt-4 pt-4 border-t border-brand-lime/20 flex justify-between items-center">
                                    <Badge className="bg-brand-lime text-brand-navy border-none shadow-sm hover:bg-brand-lime text-sm py-1">+150 XP Erhalten</Badge>
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useUserStore } from "@/store/user-store";
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragEndEvent,
} from "@dnd-kit/core";
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
    useSortable,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";

// Initial state - shuffled
const INITIAL_STEPS = [
    { id: "step-3", content: "Funk-Magnetkontakte anlernen", order: 3 },
    { id: "step-1", content: "Zentrale (WiPro III) an CAN-Bus anschließen", order: 1 },
    { id: "step-4", content: "Systemtest durchführen", order: 4 },
    { id: "step-2", content: "Spannungsversorgung (12V) herstellen", order: 2 },
];

const SortableItem = ({
    id,
    content,
    isCorrectPosition,
    showValidation,
}: {
    id: string;
    content: string;
    isCorrectPosition?: boolean;
    showValidation: boolean;
}) => {
    const { attributes, listeners, setNodeRef, transform, transition } = useSortable({ id });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
    };

    return (
        <div
            ref={setNodeRef}
            style={style}
            {...attributes}
            {...listeners}
            className={`p-5 mb-3 bg-background border-2 rounded-xl flex items-center gap-4 cursor-grab active:cursor-grabbing shadow-sm hover:border-brand-sky/50 transition-colors ${showValidation
                ? isCorrectPosition
                    ? "border-brand-lime/50 bg-brand-lime/5"
                    : "border-brand-red/50 bg-brand-red/5"
                : "border-border"
                }`}
        >
            <div className="text-muted-foreground/50 flex flex-col gap-1.5 cursor-grab">
                <div className="w-6 h-1 bg-current rounded-full"></div>
                <div className="w-6 h-1 bg-current rounded-full"></div>
                <div className="w-6 h-1 bg-current rounded-full"></div>
            </div>
            <span className="font-bold text-foreground text-sm sm:text-base">{content}</span>

            {showValidation && (
                <div className="ml-auto text-2xl">{isCorrectPosition ? "✅" : "❌"}</div>
            )}
        </div>
    );
};

export function DragAndDropQuiz() {
    const [items, setItems] = useState(INITIAL_STEPS);
    const [isValidated, setIsValidated] = useState(false);
    const [xpEarned, setXpEarned] = useState(0);
    const [isMounted, setIsMounted] = useState(false);
    const addXp = useUserStore((state) => state.addXp);

    useEffect(() => {
        setIsMounted(true);
    }, []);

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates,
        })
    );

    const handleDragEnd = (event: DragEndEvent) => {
        const { active, over } = event;

        if (active.id !== over?.id) {
            setItems((items) => {
                const oldIndex = items.findIndex((item) => item.id === active.id);
                const newIndex = items.findIndex((item) => item.id === over?.id);
                return arrayMove(items, oldIndex, newIndex);
            });
        }
        setIsValidated(false); // Reset validation on drag
    };

    const validateOrder = () => {
        setIsValidated(true);
        const isAllCorrect = items.every((item, index) => item.order === index + 1);
        if (isAllCorrect && xpEarned === 0) {
            setXpEarned(30);
            addXp(30);
        }
    };

    const isAllCorrect = isValidated && items.every((item, index) => item.order === index + 1);

    return (
        <Card className="border-border bg-muted/10 p-0 overflow-hidden max-w-3xl mx-auto w-full">
            <div className="p-6 md:p-8 flex justify-between items-start mb-2 border-b border-border bg-background">
                <div>
                    <Badge variant="secondary" className="mb-3 bg-brand-sky/10 text-brand-sky hover:bg-brand-sky/20">
                        Sortierungs-Szenario
                    </Badge>
                    <h3 className="text-2xl font-bold text-brand-navy">Montage-Reihenfolge</h3>
                    <p className="text-sm text-muted-foreground mt-1">
                        Bringen Sie die Einbauschritte der WiPro III in die richtige Reihenfolge (Drag & Drop).
                    </p>
                </div>
                <div className="text-right hidden sm:block">
                    <span className="text-lg text-brand-sky font-extrabold">+30 XP</span>
                </div>
            </div>

            <div className="max-w-xl mx-auto py-8 px-4 md:px-0">
                {isMounted ? (
                    <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                        <SortableContext items={items.map((i) => i.id)} strategy={verticalListSortingStrategy}>
                            {items.map((item, index) => (
                                <SortableItem
                                    key={item.id}
                                    id={item.id}
                                    content={item.content}
                                    showValidation={isValidated}
                                    isCorrectPosition={item.order === index + 1}
                                />
                            ))}
                        </SortableContext>
                    </DndContext>
                ) : (
                    <div className="flex flex-col gap-3 opacity-50">
                        {items.map((item) => (
                            <div key={item.id} className="p-5 bg-background border-2 rounded-xl flex items-center gap-4 border-border">
                                <div className="text-muted-foreground/50 flex flex-col gap-1.5">
                                    <div className="w-6 h-1 bg-current rounded-full"></div>
                                    <div className="w-6 h-1 bg-current rounded-full"></div>
                                    <div className="w-6 h-1 bg-current rounded-full"></div>
                                </div>
                                <span className="font-bold text-foreground text-sm sm:text-base">{item.content}</span>
                            </div>
                        ))}
                    </div>
                )}

                <div className="mt-10 flex flex-col items-center">
                    {isAllCorrect ? (
                        <Badge className="text-base py-3 px-8 animate-fade-in bg-brand-lime text-brand-navy hover:bg-brand-lime border-none shadow-md">
                            Perfekt! +30 XP
                        </Badge>
                    ) : (
                        <Button size="lg" onClick={validateOrder} className="w-full sm:w-auto px-10 py-6 text-lg">
                            Reihenfolge prüfen
                        </Button>
                    )}
                </div>
            </div>
        </Card>
    );
}

"use client";

import React, { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useUserStore } from "@/store/user-store";

// Mock Hotspot Interface
interface Hotspot {
    id: string;
    x: number;
    y: number;
    label: string;
    isCorrect: boolean;
    feedback: string;
}

const HIGHLIGHT_HOTSPOTS: Hotspot[] = [
    {
        id: "1",
        x: 25,
        y: 70,
        label: "Bodenblech Karosserie (Korrekt)",
        isCorrect: true,
        feedback:
            "Korrekt! Das Bodenblech oder die Gurtverschraubung sind ideale Massepunkte, da Karosserieteile den besten Kontakt bieten.",
    },
    {
        id: "2",
        x: 60,
        y: 30,
        label: "Plastikverkleidung C-Säule",
        isCorrect: false,
        feedback: "Falsch. Plastikverkleidungen leiten nicht und sind als Massepunkt ungeeignet.",
    },
    {
        id: "3",
        x: 80,
        y: 80,
        label: "Schraube Rückleuchte",
        isCorrect: false,
        feedback:
            "Risiko: Schlechter Kontakt oder Störeinstrahlung der Fahrzeugelektronik. Besser direkt an die Fahrzeugmasse gehen.",
    },
];

export function HotspotQuiz() {
    const [selectedHotspots, setSelectedHotspots] = useState<string[]>([]);
    const [xpEarned, setXpEarned] = useState(0);
    const addXp = useUserStore((state) => state.addXp);

    const handleHotspotClick = (hotspot: Hotspot) => {
        if (selectedHotspots.includes(hotspot.id)) return;

        setSelectedHotspots((prev) => [...prev, hotspot.id]);

        if (hotspot.isCorrect && xpEarned === 0) {
            setXpEarned(20);
            addXp(20);
        }
    };

    return (
        <Card className="border-border bg-white group p-0 overflow-hidden relative w-full max-w-4xl mx-auto">
            <div className="p-6 md:p-8 border-b border-border flex justify-between items-center bg-muted/30">
                <div>
                    <Badge variant="secondary" className="mb-3 bg-brand-sky/10 text-brand-sky hover:bg-brand-sky/20">
                        Interaktive Grafik (H5P-Style)
                    </Badge>
                    <h3 className="text-2xl font-bold text-brand-navy">Wo ist der richtige Massepunkt?</h3>
                    <p className="text-sm text-muted-foreground mt-1">
                        Wählen Sie den perfekten Massepunkt für das Einbau-Szenario.
                    </p>
                </div>
                <div className="text-right hidden sm:block">
                    <span className="text-lg text-brand-sky font-extrabold">+20 XP</span>
                    <span className="block text-xs text-muted-foreground font-medium">3 Versuche übrig</span>
                </div>
            </div>

            {/* Interaktiver Bildbereich (Fake Background) */}
            <div className="relative w-full h-96 bg-brand-navy overflow-hidden flex items-center justify-center">
                <div className="absolute inset-0 bg-gradient-to-br from-brand-sky/20 to-brand-navy"></div>

                {/* Platzhalter-Fahrzeuggrafik */}
                <div className="absolute inset-0 opacity-20 pointer-events-none flex flex-col items-center justify-center">
                    <div className="w-64 h-32 border-4 border-white rounded-t-full mb-4"></div>
                    <div className="w-96 h-24 border-4 border-white rounded-lg flex justify-between px-8">
                        <div className="w-16 h-16 border-4 border-white rounded-full -mb-8 self-end bg-brand-navy"></div>
                        <div className="w-16 h-16 border-4 border-white rounded-full -mb-8 self-end bg-brand-navy"></div>
                    </div>
                </div>

                <span className="text-white/40 text-2xl font-extrabold tracking-widest relative z-10">
                    [FAHRZEUG-HECK]
                </span>

                {/* Render Hotspots */}
                {HIGHLIGHT_HOTSPOTS.map((hotspot) => {
                    const isSelected = selectedHotspots.includes(hotspot.id);
                    const isCorrect = hotspot.isCorrect;

                    return (
                        <button
                            key={hotspot.id}
                            onClick={() => handleHotspotClick(hotspot)}
                            className={`absolute w-14 h-14 -ml-7 -mt-7 rounded-full flex items-center justify-center transition-all z-20 ${isSelected
                                ? isCorrect
                                    ? "bg-brand-lime scale-110 shadow-lg text-brand-navy animate-pulse"
                                    : "bg-brand-red scale-90 opacity-80 text-white"
                                : "bg-brand-sky/80 hover:bg-brand-sky hover:scale-110 text-white shadow-xl ring-4 ring-white/30 cursor-pointer animate-float"
                                }`}
                            style={{ top: `${hotspot.y}%`, left: `${hotspot.x}%` }}
                        >
                            {isSelected ? (isCorrect ? "✓" : "✗") : "?"}
                        </button>
                    );
                })}
            </div>

            {/* Feedback Bereich */}
            <CardContent className="p-6 md:p-8 min-h-[160px] bg-muted/10">
                {selectedHotspots.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-center space-y-3">
                        <div className="text-4xl opacity-50">👆</div>
                        <p className="text-muted-foreground italic font-medium">
                            Klicken Sie auf ein Plus-Symbol im Bild, um einen Punkt zu validieren.
                        </p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {selectedHotspots.map((id) => {
                            const hotspot = HIGHLIGHT_HOTSPOTS.find((h) => h.id === id);
                            if (!hotspot) return null;

                            return (
                                <div
                                    key={id}
                                    className={`p-4 rounded-xl flex items-start gap-4 animate-fade-in border shadow-sm ${hotspot.isCorrect
                                        ? "bg-brand-lime/10 border-brand-lime/30"
                                        : "bg-brand-red/5 border-brand-red/20"
                                        }`}
                                >
                                    <div className="mt-1 text-3xl">{hotspot.isCorrect ? "✅" : "⚠️"}</div>
                                    <div className="flex-1">
                                        <h4
                                            className={`font-bold text-base mb-1 ${hotspot.isCorrect ? "text-brand-navy" : "text-brand-red"
                                                }`}
                                        >
                                            {hotspot.label}
                                        </h4>
                                        <p
                                            className={`text-sm leading-relaxed ${hotspot.isCorrect ? "text-foreground" : "text-muted-foreground"
                                                }`}
                                        >
                                            {hotspot.feedback}
                                        </p>
                                    </div>
                                </div>
                            );
                        })}

                        {xpEarned > 0 && (
                            <div className="pt-4 text-center animate-fade-in">
                                <Badge className="text-base px-8 py-3 shadow-md bg-brand-lime hover:bg-brand-lime text-brand-navy border-none">
                                    Super gelöst! +{xpEarned} XP erhalten.
                                </Badge>
                            </div>
                        )}
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

