"use client";

// src/lib/multiplayer/Scoreboard.tsx
// End-screen component with rankings, confetti, and play-again

import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { useTranslations } from "next-intl";
import { Trophy, RotateCcw, Star } from "lucide-react";
import type { Participant } from "./types";

interface ScoreboardProps {
  participants: Participant[];
  hostName: string;
  isHost: boolean;
  onPlayAgain?: () => void;
}

// Confetti particle component (CSS-only)
function ConfettiParticle({ index }: { index: number }) {
  const colors = ["#C7F464", "#FFD700", "#FF6B9D", "#00C9FF", "#A78BFA", "#4ECDC4"];
  const color = colors[index % colors.length];
  const left = Math.random() * 100;
  const delay = Math.random() * 2;
  const duration = 2 + Math.random() * 2;
  const size = 6 + Math.random() * 8;

  return (
    <motion.div
      initial={{ y: -20, x: 0, opacity: 1, rotate: 0 }}
      animate={{
        y: [0, 400, 600],
        x: [0, (Math.random() - 0.5) * 200],
        opacity: [1, 1, 0],
        rotate: [0, 360 * (Math.random() > 0.5 ? 1 : -1)],
      }}
      transition={{
        duration,
        delay,
        ease: "easeOut",
      }}
      style={{
        position: "absolute",
        top: 0,
        left: `${left}%`,
        width: size,
        height: size * 0.6,
        backgroundColor: color,
        borderRadius: 2,
        pointerEvents: "none",
        zIndex: 50,
      }}
    />
  );
}

export function Scoreboard({
  participants,
  hostName,
  isHost,
  onPlayAgain,
}: ScoreboardProps) {
  const t = useTranslations("multiplayer.scoreboard");
  const [showConfetti, setShowConfetti] = useState(true);

  // Sort by score descending
  const ranked = [...participants].sort((a, b) => b.score - a.score);
  const medals = ["🥇", "🥈", "🥉"];

  useEffect(() => {
    const timer = setTimeout(() => setShowConfetti(false), 5000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="relative max-w-2xl mx-auto">
      {/* Confetti for 1st place */}
      {showConfetti && ranked.length > 0 && (
        <div className="fixed inset-0 pointer-events-none overflow-hidden z-50">
          {Array.from({ length: 40 }).map((_, i) => (
            <ConfettiParticle key={i} index={i} />
          ))}
        </div>
      )}

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-3xl p-8 shadow-2xl"
      >
        {/* Header */}
        <div className="text-center mb-8">
          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ type: "spring", delay: 0.2 }}
            className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-brand-lime/20 mb-4"
          >
            <Trophy className="w-8 h-8 text-brand-lime" />
          </motion.div>
          <h2 className="text-3xl font-black text-white mb-2">
            {t("title")}
          </h2>
          {ranked.length > 0 && (
            <p className="text-brand-lime font-bold">
              {t("winner")}: {ranked[0].name} 🎉
            </p>
          )}
        </div>

        {/* Rankings */}
        <div className="space-y-2 mb-8">
          {ranked.map((p, i) => (
            <motion.div
              key={p.id}
              initial={{ opacity: 0, x: -30 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.3 + i * 0.1 }}
              className={`flex items-center gap-4 p-4 rounded-xl transition-all ${
                i === 0
                  ? "bg-brand-lime/10 border border-brand-lime/30"
                  : i === 1
                  ? "bg-white/8 border border-white/15"
                  : i === 2
                  ? "bg-amber-500/5 border border-amber-500/15"
                  : "bg-white/3 border border-white/5"
              }`}
            >
              {/* Rank */}
              <div className="w-10 text-center text-2xl">
                {i < 3 ? medals[i] : (
                  <span className="text-white/40 text-lg font-bold">{i + 1}.</span>
                )}
              </div>

              {/* Avatar + Name */}
              <div className="flex-1 min-w-0">
                <p className={`font-bold truncate ${
                  i === 0 ? "text-brand-lime text-lg" : "text-white"
                }`}>
                  {p.name}
                </p>
              </div>

              {/* Score */}
              <div className="text-right">
                <div className="flex items-center gap-1">
                  <Star className={`w-4 h-4 ${
                    i === 0 ? "text-brand-lime" : "text-white/40"
                  }`} />
                  <span className={`font-black text-lg ${
                    i === 0 ? "text-brand-lime" : "text-white"
                  }`}>
                    {p.score.toLocaleString()}
                  </span>
                </div>
                <p className="text-white/30 text-xs">Punkte</p>
              </div>
            </motion.div>
          ))}

          {ranked.length === 0 && (
            <div className="text-center py-8 text-white/40">
              Keine Teilnehmer
            </div>
          )}
        </div>

        {/* Play Again (Host only) */}
        {isHost && onPlayAgain && (
          <motion.button
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={onPlayAgain}
            className="w-full py-3 rounded-xl font-bold text-lg bg-brand-lime text-brand-navy hover:bg-brand-lime/90 transition-all flex items-center justify-center gap-2"
          >
            <RotateCcw className="w-5 h-5" />
            {t("playAgain")}
          </motion.button>
        )}
      </motion.div>
    </div>
  );
}

import { createServerClient } from "@supabase/ssr";
import { NextResponse, type NextRequest } from "next/server";
import { routing } from "@/i18n/routing";

// Routes that don't require authentication
const PUBLIC_ROUTES = ["/login", "/register", "/forgot-password", "/api/auth"];

export async function updateSession(request: NextRequest) {
    let supabaseResponse = NextResponse.next({ request });

    // Demo mode: skip real auth
    if (process.env.NEXT_PUBLIC_DEMO_MODE === "true") {
        return supabaseResponse;
    }

    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: {
                getAll() {
                    return request.cookies.getAll();
                },
                setAll(cookiesToSet) {
                    cookiesToSet.forEach(({ name, value }) =>
                        request.cookies.set(name, value)
                    );
                    supabaseResponse = NextResponse.next({ request });
                    cookiesToSet.forEach(({ name, value, options }) =>
                        supabaseResponse.cookies.set(name, value, options)
                    );
                },
            },
        }
    );

    const {
        data: { user },
    } = await supabase.auth.getUser();

    const isPublicRoute = PUBLIC_ROUTES.some((route) => {
        if (request.nextUrl.pathname === route) return true;
        return routing.locales.some((locale) => request.nextUrl.pathname === `/${locale}${route}`);
    });

    // Redirect unauthenticated users to login
    if (!user && !isPublicRoute) {
        const url = request.nextUrl.clone();
        // Redirect to localized login if possible, else root /login
        const locale = request.nextUrl.pathname.split("/")[1];
        const isSupportedLocale = routing.locales.includes(locale as any);
        url.pathname = isSupportedLocale ? `/${locale}/login` : "/login";
        url.searchParams.set("redirect", request.nextUrl.pathname);
        return NextResponse.redirect(url);
    }

    // Redirect authenticated users away from login
    const isLoginPage =
        request.nextUrl.pathname === "/login" ||
        routing.locales.some((locale) => request.nextUrl.pathname === `/${locale}/login`);

    if (user && isLoginPage) {
        const redirect = request.nextUrl.searchParams.get("redirect") || "/";
        return NextResponse.redirect(new URL(redirect, request.url));
    }

    return supabaseResponse;
}

import { updateSession } from "@/lib/supabase/middleware";
import createMiddleware from "next-intl/middleware";
import { routing } from "./i18n/routing";
import type { NextRequest } from "next/server";

const intlMiddleware = createMiddleware(routing);

export async function middleware(request: NextRequest) {
    // Zuerst Supabase Auth
    const supabaseResponse = await updateSession(request);

    // Dann Next-Intl (wir verwerfen den Header/Cookie Return Wert von Supabase hier für's Erste 
    // und lassen next-intl das Routing übernehmen, da wir noch kein volles supabase SSR für locales gebaut haben)
    return intlMiddleware(request);
}

export const config = {
    matcher: [
        // Match all paths except API, _next/static, images, HTML files, etc.
        "/((?!api|_next/static|_next/image|favicon.ico|icons|manifest.json|.*\\.(?:svg|png|jpg|jpeg|gif|webp|pdf|html)$).*)",
    ],
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export type UserRole = 'admin' | 'manager' | 'user';

export interface AuthUser {
    id: string;
    email: string;
    name: string;
    company: string;
    dealerId: string;
    role: UserRole;
    region: string;
    avatar?: string;
}

interface AuthState {
    user: AuthUser | null;
    isAuthenticated: boolean;
    isLoading: boolean;
    isDemoMode: boolean;
    login: (email: string, password: string) => Promise<{ success: boolean; error?: string }>;
    register: (data: RegisterData) => Promise<{ success: boolean; error?: string }>;
    logout: () => void;
    setUser: (user: AuthUser | null) => void;
}

interface RegisterData {
    email: string;
    password: string;
    name: string;
    company: string;
    dealerId: string;
    region: string;
}

// Demo users for testing without Supabase
const DEMO_USERS: Record<string, AuthUser & { password: string }> = {
    'admin@thitronik.de': {
        id: 'demo-admin-001',
        email: 'admin@thitronik.de',
        name: 'Anna Thitronik',
        company: 'THITRONIK GmbH',
        dealerId: 'TH-ADMIN',
        role: 'admin',
        region: 'DACH',
        password: 'admin',
    },
    'manager@autohaus.de': {
        id: 'demo-manager-001',
        email: 'manager@autohaus.de',
        name: 'Frank Weber',
        company: 'Caravan Center Kiel',
        dealerId: 'TH-DE-0312',
        role: 'manager',
        region: 'Deutschland Nord',
        password: 'manager',
    },
    'max@autohaus.de': {
        id: 'demo-user-001',
        email: 'max@autohaus.de',
        name: 'Max Mustermann',
        company: 'Autohaus Mustermann GmbH',
        dealerId: 'TH-DE-0849',
        role: 'user',
        region: 'Deutschland Nord',
        password: 'demo',
    },
};

export const useAuthStore = create<AuthState>()(
    persist(
        (set) => {
            const isDemo = process.env.NEXT_PUBLIC_DEMO_MODE === 'true';
            const defaultUser: AuthUser | null = null; // Don't force a user on load

            return {
                user: defaultUser,
                isAuthenticated: !!defaultUser, // Only authenticated if defaultUser is set (which is null in demo mode initially now)
                isLoading: false,
                isDemoMode: isDemo,

                login: async (email: string, password: string) => {
                    set({ isLoading: true });

                    // Demo mode: check against local demo users
                    if (process.env.NEXT_PUBLIC_DEMO_MODE === 'true') {
                        await new Promise((r) => setTimeout(r, 800)); // Simulate network
                        const demoUser = DEMO_USERS[email.toLowerCase()];
                        if (demoUser && demoUser.password === password) {
                            const { password: _, ...user } = demoUser;
                            set({ user, isAuthenticated: true, isLoading: false });
                            return { success: true };
                        }
                        set({ isLoading: false });
                        return { success: false, error: 'Ungültige Zugangsdaten. Demo-Accounts: admin@thitronik.de / max@autohaus.de' };
                    }

                    // Real Supabase Auth
                    try {
                        const { createClient } = await import('@/lib/supabase/client');
                        const supabase = createClient();
                        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
                        if (error) {
                            set({ isLoading: false });
                            return { success: false, error: error.message };
                        }
                        // Fetch user profile from custom users table
                        const { data: profile } = await supabase
                            .from('users')
                            .select('*')
                            .eq('auth_id', data.user.id)
                            .single();

                        const user: AuthUser = {
                            id: data.user.id,
                            email: data.user.email || email,
                            name: profile?.full_name || email.split('@')[0],
                            company: profile?.company || '',
                            dealerId: profile?.dealer_id || '',
                            role: profile?.role || 'user',
                            region: profile?.region || 'DACH',
                        };
                        set({ user, isAuthenticated: true, isLoading: false });
                        return { success: true };
                    } catch (err) {
                        set({ isLoading: false });
                        return { success: false, error: 'Verbindungsfehler. Bitte versuchen Sie es erneut.' };
                    }
                },

                register: async (data: RegisterData) => {
                    set({ isLoading: true });

                    if (process.env.NEXT_PUBLIC_DEMO_MODE === 'true') {
                        await new Promise((r) => setTimeout(r, 1000));
                        const user: AuthUser = {
                            id: `demo-${Date.now()}`,
                            email: data.email,
                            name: data.name,
                            company: data.company,
                            dealerId: data.dealerId,
                            role: 'user',
                            region: data.region,
                        };
                        set({ user, isAuthenticated: true, isLoading: false });
                        return { success: true };
                    }

                    try {
                        const { createClient } = await import('@/lib/supabase/client');
                        const supabase = createClient();
                        const { error } = await supabase.auth.signUp({
                            email: data.email,
                            password: data.password,
                            options: { data: { full_name: data.name, company: data.company, dealer_id: data.dealerId, region: data.region } },
                        });
                        if (error) {
                            set({ isLoading: false });
                            return { success: false, error: error.message };
                        }
                        set({ isLoading: false });
                        return { success: true };
                    } catch {
                        set({ isLoading: false });
                        return { success: false, error: 'Registrierung fehlgeschlagen.' };
                    }
                },

                logout: () => {
                    set({ user: null, isAuthenticated: false });
                    if (process.env.NEXT_PUBLIC_DEMO_MODE !== 'true') {
                        import('@/lib/supabase/client').then(({ createClient }) => {
                            createClient().auth.signOut();
                        });
                    }
                },

                setUser: (user) => set({ user, isAuthenticated: !!user }),
            };
        },
        { name: 'campus-auth', partialize: (state) => ({ user: state.user, isAuthenticated: state.isAuthenticated }) }
    )
);

// Role check helpers
export const isAdmin = (user: AuthUser | null) => user?.role === 'admin';
export const isManager = (user: AuthUser | null) => user?.role === 'manager' || user?.role === 'admin';
export const hasRole = (user: AuthUser | null, role: UserRole) => {
    if (!user) return false;
    if (user.role === 'admin') return true;
    if (user.role === 'manager' && role !== 'admin') return true;
    return user.role === role;
};
